// radio_golden_24_s3.js — MedGolden Radiology (SK-RADIOLOGY 3rd Edition, vol 24, Set 3) recall MCQs
// Schema: {q,o,a,e} to match platform reader. 1:1 book numbering /*N*/.
// Take Notes line is a meaningful differentiator, never a bare restatement.
if(!window.MM) window.MM={};
window.MM['radio_golden_24_s3']=[
/*1*/ {"q":"Cerebellar damage sign is:","o":["Dysmetria","Loss of memory","Dyslexia","Tremor at rest"],"a":0,"e":"Cerebellar damage causes ipsilateral signs including dysmetria (inability to judge distance/force of movement), dysdiadochokinesia, intention tremor, and ataxia. Resting tremor is a basal ganglia sign, not cerebellar.<br><br>Take Notes: Dysmetria → cerebellar (past-pointing on finger-nose test) | Resting tremor → Parkinson's/basal ganglia | Loss of memory → hippocampus | Dyslexia → dominant parietal lobe."},
/*2*/ {"q":"Which of the following lung volumes or capacities can be measured by spirometry?","o":["FRC","Physiologic dead space","RV","VC"],"a":3,"e":"Spirometry directly measures volumes that can be exhaled or inhaled: tidal volume, IRV, ERV, and vital capacity (VC = IRV + TV + ERV). FRC and RV contain trapped air that cannot be exhaled, requiring helium dilution or body plethysmography.<br><br>Take Notes: VC → measured by spirometry (sum of IRV + TV + ERV) | FRC and RV → NOT measurable by spirometry (need helium dilution) | TLC = VC + RV → also not directly by spirometry."},
/*3*/ {"q":"A young boy came in ER with profuse bleeding from minor trauma for last 6 months, no family history, also chronic diarrhea, bleeding time 6 mins, clotting time 30 min. Most likely cause is:","o":["Christmas disease","Classical disease","Liver failure","Vitamin K deficiency"],"a":3,"e":"Prolonged clotting time (PT/APTT affected) with normal bleeding time and no family history, combined with chronic diarrhoea (malabsorption of fat-soluble vitamins), points to Vitamin K deficiency. Vitamin K is required for factors II, VII, IX, X.<br><br>Take Notes: Vitamin K deficiency → prolonged PT + APTT (not bleeding time) | Christmas disease → Factor IX deficiency (X-linked, family history expected) | Chronic diarrhoea → fat-soluble vitamin malabsorption → Vitamin K deficiency."},
/*4*/ {"q":"11 year old girl was sent to radiologist for X-ray elbow joint to diagnose the age. The secondary centre of ossification last to appear in her humerus is:","o":["Medial epicondyle","Lateral epicondyle","Rochlea","Capitulum"],"a":0,"e":"The mnemonic CRITOE describes the order of elbow ossification centres: Capitulum (1yr), Radial head (3yr), Internal/medial epicondyle (5yr), Trochlea (7yr), Olecranon (9yr), External/lateral epicondyle (11yr). Medial epicondyle appears at age 5 but is the LAST to fuse (age 18-20).<br><br>Take Notes: CRITOE → order of appearance | Medial epicondyle → last to FUSE (not last to appear) | Lateral epicondyle → last to appear (age 11) | At age 11 in a girl → medial epicondyle is the key unfused centre."},
/*5*/ {"q":"Regarding blood supply of brain??","o":["Middle cerebral artery supplies premotor cortex","Cerebral arteries don't anastomose on surface of brain","Branches of cerebral artery don't anastomose after entering brain","Internal capsule supplied by central branches of anterior cerebral artery"],"a":2,"e":"Once cerebral arteries penetrate the brain substance, they become end arteries with no functional anastomoses — making their territories vulnerable to infarction. On the brain surface, there ARE anastomoses between vessels.<br><br>Take Notes: cerebral arteries → anastomose on surface (leptomeningeal collaterals) | After entering brain → end arteries (no anastomosis) | Internal capsule → supplied by lenticulostriate branches of MCA (not ACA) | End arteries = no collateral rescue if occluded."},
/*6*/ {"q":"A female patient presented with pain hypochondrium. Exploratory laparotomy showed ovaries attached to lateral pelvic wall. Which structure in this area has increased risk of damage during procedure?","o":["Ovarian artery","Uterine artery","Internal iliac artery","Femoral artery"],"a":1,"e":"During hysterectomy and ovarian surgery, the ureter is at greatest risk at three points: where it crosses the uterine artery ('water under the bridge'), at the pelvic brim crossing the common iliac, and near the internal iliac. The uterine artery lies directly over the ureter.<br><br>Take Notes: ureter at risk → where uterine artery crosses it ('water under bridge') | Cardinal ligament → contains uterine vessels overlying ureter | Internal iliac artery → gives uterine artery | Uterine artery = the structure overlying the ureter = surgical danger."},
/*7*/ {"q":"Unmyelinated nociceptive primary afferent fibers synapses directly which neuron of spinal cord?","o":["Spinothalamic neuron of lamina 1","Flexor motor neuron","Ventral spinocerebellar track neuron","Preganglionic sympathetic neuron"],"a":0,"e":"Unmyelinated C fibres (slow pain, temperature) and A-delta fibres (fast pain) synapse in the dorsal horn — C fibres primarily in lamina I (marginal zone) and lamina II (substantia gelatinosa). Lamina I neurons project via the spinothalamic tract to the thalamus.<br><br>Take Notes: C fibres (unmyelinated) → synapse in lamina I and II (dorsal horn) | A-delta → lamina I and V | Spinothalamic tract neuron in lamina I → second-order neuron for pain | Lamina I = marginal zone = nociceptive relay."},
/*8*/ {"q":"Edema of renal origin is most likely due to:","o":["HTN","Renal stones","Ca retention by kidney","Albuminuria and Na retention"],"a":3,"e":"Renal oedema results from two mechanisms: loss of plasma proteins (hypoalbuminaemia from proteinuria reducing oncotic pressure) and sodium/water retention by the kidney (increasing hydrostatic pressure). Both mechanisms operate in nephrotic and nephritic syndromes.<br><br>Take Notes: nephrotic oedema → hypoalbuminaemia (proteinuria) → reduced oncotic pressure | nephritic oedema → Na/water retention → increased hydrostatic pressure | Both albuminuria AND Na retention = the complete renal oedema mechanism."},
/*9*/ {"q":"In extradural hematoma artery involved will be:","o":["ACA","Bridging veins","PCA","MMA"],"a":3,"e":"Extradural (epidural) haematoma results from rupture of the middle meningeal artery (MMA), typically following a temporal bone fracture. The classic presentation is a lucid interval followed by rapid neurological deterioration as the arterial bleed expands.<br><br>Take Notes: EDH → MMA (middle meningeal artery, arterial) | SDH → bridging veins (venous, slower) | Lucid interval → classic EDH feature | MMA runs in epidural space after entering via foramen spinosum."},
/*10*/ {"q":"Oral (buccopharyngeal) membrane separates:","o":["Amniotic sac from yolk sac","Larynx from pharynx","Nasal cavity from oral cavity","Stomodeum from foregut"],"a":3,"e":"The buccopharyngeal membrane (oral plate) is a bilaminar membrane (ectoderm + endoderm) that separates the stomodeum (ectoderm-lined future mouth) from the foregut (endoderm-lined). It ruptures at week 4 of development to open the oral cavity.<br><br>Take Notes: buccopharyngeal membrane → separates stomodeum (ectoderm) from foregut (endoderm) | Ruptures week 4 → opens mouth | Proctodeal membrane → separates hindgut from proctodeum (equivalent at caudal end) | Stomodeum + foregut = what it separates."},
/*11*/ {"q":"Plasma proteins filtered in minute amount from kidney because filtration is opposed by membrane due to:","o":["Negative charge of proteoglycan on basement membrane","Large size","Positive charge","Medium size"],"a":0,"e":"The glomerular filtration barrier has two selectivity mechanisms: size (type IV collagen in lamina densa) and charge (heparan sulphate proteoglycans in laminae rarae carry negative charge). Plasma proteins like albumin are also negatively charged and are repelled by the negative GBM charge.<br><br>Take Notes: GBM charge barrier → negative heparan sulphate → repels negatively charged albumin | Size barrier → lamina densa (type IV collagen) | Nephrotic syndrome → charge barrier lost first → albuminuria | Negative charge = the charge-selective filtration barrier."},
/*12*/ {"q":"70 years old man with renal transplant 2 years back, now presented with complicated pneumonia not responding to antibiotics. Bronchoalveolar lavage shows boat shaped cyst. The organism causing the condition is:","o":["Pneumocystic jiroveci","Candida albicans","Mycoplasma tuberculosis","Treponema pallidum"],"a":0,"e":"Post-transplant immunosuppression predisposes to Pneumocystis jirovecii pneumonia (PJP). BAL showing boat-shaped cysts (with Gomori methenamine silver stain) is pathognomonic. PJP is the most common life-threatening opportunistic infection in immunosuppressed patients.<br><br>Take Notes: PJP → boat-shaped/crescent cysts on BAL (GMS stain) | Post-transplant → most common opportunistic fungal-like pneumonia | TMP-SMX → prophylaxis and treatment | Candida → oral/oesophageal, not typical BAL cysts."},
/*13*/ {"q":"Which bacteria has no cell wall?","o":["Chlamydia","Mycoplasma","Klebsiella","E. coli"],"a":1,"e":"Mycoplasma lacks a cell wall entirely — it is the smallest self-replicating organism. This makes it inherently resistant to all beta-lactam antibiotics (which target cell wall synthesis) and explains why it cannot be Gram stained.<br><br>Take Notes: Mycoplasma → no cell wall → resistant to all beta-lactams | Chlamydia → has cell wall but lives intracellularly | Treatment for Mycoplasma → macrolides, tetracyclines, fluoroquinolones | No cell wall = Mycoplasma = classic MCQ fact."},
/*14*/ {"q":"Theophyllin cause more affect in children in due to:","o":["Increase metabolism","Decrease excretion","Increase receptors","Decrease receptors"],"a":1,"e":"Children have decreased hepatic clearance of theophylline (immature cytochrome P450 enzyme system), leading to reduced excretion and drug accumulation. This narrow therapeutic index drug causes toxicity (seizures, arrhythmias) more readily in children.<br><br>Take Notes: theophylline in children → decreased hepatic excretion (immature CYP enzymes) → drug accumulation | Narrow therapeutic index → toxicity at slightly elevated levels | Adults → faster metabolism | Decreased excretion = the mechanism of increased effect in children."},
/*15*/ {"q":"Cimetidine given before surgery because:","o":["Decrease acidity","Decrease volume of gastric acid","Potent H2 receptor blocker","Increase gastrin"],"a":1,"e":"Cimetidine (H2 blocker) is given pre-operatively to reduce both the volume and acidity of gastric contents, minimising the risk of Mendelson's syndrome (acid aspiration pneumonitis) during induction of anaesthesia. Reducing volume is key to aspiration risk reduction.<br><br>Take Notes: pre-op cimetidine → reduces gastric volume + acidity | Mendelson's syndrome → acid aspiration pneumonitis (pH <2.5, volume >25ml = dangerous) | Ranitidine/omeprazole → also used | Reducing volume = the primary surgical reason."},
/*16*/ {"q":"A diabetic patient presented in OPD with oozing greenish discharge from wound. Which of following is causative agent?","o":["Bacteriods","E.coli","Listeria","Pseudomonas"],"a":3,"e":"Pseudomonas aeruginosa produces a blue-green pigment (pyocyanin + pyoverdine) causing characteristic greenish wound discharge. It is an opportunistic gram-negative rod, common in diabetic wounds, burns, and hospital-acquired infections.<br><br>Take Notes: green wound discharge → Pseudomonas aeruginosa (pyocyanin pigment) | Diabetic wounds → Pseudomonas + Staph + anaerobes | Treatment → anti-pseudomonal penicillins, carbapenems, aminoglycosides | Green colour = Pseudomonas = the pigment clue."},
/*17*/ {"q":"Pale infarct in heart as a result of MI is related to which necrosis:","o":["Caseous necrosis","Liquefactive necrosis","Coagulative necrosis","Fibrinoid necrosis"],"a":2,"e":"Myocardial infarction causes coagulative necrosis — ischaemia denatures enzymes while preserving the structural protein scaffold, giving ghost cell outlines. The heart and solid organs (kidney, spleen, liver) undergo coagulative necrosis from ischaemia.<br><br>Take Notes: coagulative necrosis → MI + solid organ ischaemia (ghost cells preserved) | Liquefactive → brain + abscesses | Caseous → TB/fungi | Fibrinoid → vasculitis/malignant hypertension | Heart infarct = coagulative = ghost cell outlines."},
/*18*/ {"q":"Chorionic villus sampling done at which week?","o":["11-12 week","14-16 week","19 week","8-10 week"],"a":0,"e":"CVS is performed at 10-13 weeks gestation (most commonly 11-12 weeks), allowing first-trimester prenatal diagnosis. It carries ~1% miscarriage risk. Amniocentesis is performed at 15-20 weeks; cordocentesis at 20+ weeks.<br><br>Take Notes: CVS → 10-13 weeks (11-12 most common), 1% miscarriage risk | Amniocentesis → 15-20 weeks, 0.5% risk | Cordocentesis → 20+ weeks, 2-5% risk | Earliest prenatal test = CVS."},
/*19*/ {"q":"RBCs synthesize ATP from glucose. Glycolysis enzyme present in:","o":["Nucleus","Cytoplasm of RBC","Mitochondria","Cell membrane"],"a":1,"e":"RBCs lack mitochondria and rely entirely on anaerobic glycolysis in the cytoplasm for ATP production. Glycolytic enzymes (hexokinase, PFK, pyruvate kinase) are all cytosolic. Deficiency of these enzymes causes haemolytic anaemia.<br><br>Take Notes: RBC energy → anaerobic glycolysis only (no mitochondria, no Krebs, no OXPHOS) | Glycolytic enzymes → cytoplasm | PK deficiency → haemolytic anaemia | Cytoplasm = the exclusive site of RBC ATP synthesis."},
/*20*/ {"q":"Intramitochondrial protein synthesis by:","o":["Atpase","Cytochrome","Nuclei gene","Golgi apparatus"],"a":1,"e":"Mitochondria have their own DNA and ribosomes (70S, similar to bacteria), synthesising 13 proteins of the electron transport chain — primarily cytochrome subunits. This supports the endosymbiotic theory of mitochondrial origin.<br><br>Take Notes: mitochondrial genome → encodes 13 ETC proteins (cytochrome subunits) | 70S ribosomes → inside mitochondria (like bacteria) | Nuclear genes → encode ~1500 other mitochondrial proteins | Cytochrome = the key mitochondrially-synthesised protein."},
/*21*/ {"q":"2 month old baby cause loose motion after every feed immediately due to:","o":["Lactose intolerance","Gastrocolic reflex","IBD","Psychogenic"],"a":1,"e":"The gastrocolic reflex causes colonic peristalsis in response to gastric distension after feeding — this is physiologically normal in infants, producing defaecation shortly after each feed. This reflex is most active in neonates and young infants.<br><br>Take Notes: gastrocolic reflex → feeding → gastric distension → colonic peristalsis → defaecation | Physiologically normal in infants (immediate post-feed bowel movement) | Lactose intolerance → develops after 6-8 hours of feed (gas, bloating) | Gastrocolic reflex = normal infant feeding response."},
/*22*/ {"q":"DOC of tapeworm:","o":["Albendazol","Mebendazol","Niclosamide","Metronidazole"],"a":2,"e":"Niclosamide is the drug of choice for intestinal tapeworm infections (Taenia saginata, Taenia solium intestinal form, Diphyllobothrium). It inhibits mitochondrial phosphorylation in the worm. Praziquantel is an alternative.<br><br>Take Notes: niclosamide → DOC for intestinal tapeworms (Taenia saginata, solium) | Praziquantel → alternative, also used for neurocysticercosis | Albendazole → nematodes + cysticercosis | Metronidazole → anaerobes + protozoa (not tapeworms)."},
/*23*/ {"q":"Plasma protein synthesize by which of following:","o":["Spleen","Liver","Kidney","Pancreas"],"a":1,"e":"The liver synthesises virtually all plasma proteins including albumin, clotting factors (I, II, V, VII, VIII, IX, X, XI), complement proteins, transport proteins (transferrin, haptoglobin, ceruloplasmin), and acute phase reactants. Immunoglobulins are the exception (produced by plasma cells).<br><br>Take Notes: liver → synthesises albumin + clotting factors + complement + transport proteins | Immunoglobulins → plasma cells (B cell derived, NOT liver) | Liver failure → hypoalbuminaemia + coagulopathy | Liver = the plasma protein factory."},
/*24*/ {"q":"Nerve damage between C5 and C6:","o":["C5","C6","C4","C3"],"a":0,"e":"Damage between C5 and C6 affects the C5 nerve root (Erb's point — upper trunk of brachial plexus). Erb's palsy causes 'waiter's tip' deformity: shoulder adducted, medially rotated, elbow extended, forearm pronated. Deltoid, biceps, and supraspinatus are primarily affected.<br><br>Take Notes: C5-C6 damage → Erb's palsy (upper trunk brachial plexus) | 'Waiter's tip' → shoulder IR + elbow extended | C8-T1 damage → Klumpke's palsy (lower trunk) | C5 is the damaged root when injury is between C5 and C6."},
/*25*/ {"q":"Woman having lordosis this involves which part of vertebrae:","o":["Thoracic","Spinal","Lumbar","None"],"a":2,"e":"Lordosis is an exaggerated anterior concavity of the spine. The lumbar spine has a normal lordotic curve — pathological lumbar lordosis (hyperlordosis) involves the lumbar vertebrae and is associated with obesity, pregnancy, and hip flexor tightness.<br><br>Take Notes: lordosis → anterior concavity (forward curve) → lumbar spine | Kyphosis → posterior convexity → thoracic spine | Scoliosis → lateral curvature | Lumbar hyperlordosis = pregnancy/obesity/weak core muscles."},
/*26*/ {"q":"Lattisimus dorsi nerve supply is:","o":["Median nerve","Accessory nerve","Axillary nerve","Thoracodorsal nerve"],"a":3,"e":"Latissimus dorsi is innervated by the thoracodorsal nerve (C6-C8), a branch of the posterior cord of the brachial plexus. It is the prime mover for shoulder adduction, extension, and medial rotation — the 'chin-up' muscle.<br><br>Take Notes: latissimus dorsi → thoracodorsal nerve (C6-C8, posterior cord) | Long thoracic nerve → serratus anterior (winging of scapula) | Axillary nerve → deltoid + teres minor | Thoracodorsal = latissimus dorsi = the swimming/climbing nerve."},
/*27*/ {"q":"After gunshot injury to lower back, patient has loss of contralateral pain sensation but intact temperature sensation. What is the likely diagnosis?","o":["Section of dorsal root S1","Section of ventral root S1","Brown sequard syndrome","Early stage of tabes dorsalis"],"a":2,"e":"Brown-Séquard syndrome (hemisection of spinal cord) causes ipsilateral loss of motor function, proprioception, and vibration (posterior column), with contralateral loss of pain and temperature below the lesion (spinothalamic tract crosses within 2 segments of entry).<br><br>Take Notes: Brown-Séquard → ipsilateral motor + proprioception loss | Contralateral pain + temperature loss | Gunshot/stab = classic cause | Contralateral pain loss only = the spinothalamic tract component of hemisection."},
/*28*/ {"q":"Patient with right sided hemiplegia, left sided pain and temp lost below T8 while right side proprioception and touch sensations lost below T8. What is the cause?","o":["Complete transection at T8","Hemi section at T8","Hemi section below T11","Cauda Equina"],"a":1,"e":"Right hemiplegia + right proprioception loss (ipsilateral posterior column) + left pain/temperature loss (contralateral spinothalamic) = right-sided spinal cord hemisection (Brown-Séquard) at T8. All deficits are below T8 confirming the level.<br><br>Take Notes: right hemiplegia + right proprioception loss → right posterior column + corticospinal tract | Left pain/temperature loss → left spinothalamic (crosses below T8) | This = right Brown-Séquard at T8 | Hemi-section = Brown-Séquard = the classic split-deficit pattern."},
/*29*/ {"q":"A patient with enlarged hand and feet with associated joint on MRI mass compressing optic chiasma was found. What can occur in this patient?","o":["Bitemporal hemianopia","Blindness","Binasal hemianopia","Upper quadrantanpia"],"a":0,"e":"Acromegaly is caused by a GH-secreting pituitary adenoma. As the tumour enlarges superiorly, it compresses the optic chiasma from below, damaging the crossing nasal fibres from both retinas — producing bitemporal hemianopia (loss of both temporal visual fields).<br><br>Take Notes: optic chiasma compression → bitemporal hemianopia (temporal fields lost) | Pituitary adenoma → most common cause | Compression from below → nasal retinal fibres affected → temporal field loss | Bitemporal hemianopia = the chiasmal lesion pattern."},
/*30*/ {"q":"Patient has raised prolactin and B/L temporal vision loss due to defect in:","o":["Superior optic chiasma","Lateral optic chiasma","Middle optic chiasma","Optic tract"],"a":2,"e":"A prolactin-secreting pituitary adenoma (prolactinoma) enlarges to compress the optic chiasma centrally (middle), where nasal fibres from both eyes cross. This causes bitemporal hemianopia. The chiasma is superior and anterior to the pituitary.<br><br>Take Notes: prolactinoma → middle chiasma compression | Middle chiasma → crossing nasal fibres → bitemporal hemianopia | Optic tract lesion → contralateral homonymous hemianopia | Middle chiasma = the pituitary adenoma compression site."},
/*31*/ {"q":"Gunshot wound injury result in damage to sciatic nerve. Which muscle will be spared?","o":["Bicep femoris","Semitendinous","Semimembranous","Gluteus maximus"],"a":3,"e":"The sciatic nerve supplies all hamstrings (biceps femoris, semitendinosus, semimembranosus) and all muscles below the knee. Gluteus maximus is supplied by the inferior gluteal nerve (L5-S2), which is separate from the sciatic nerve — it is therefore spared.<br><br>Take Notes: sciatic nerve → hamstrings + all muscles below knee | Gluteus maximus → inferior gluteal nerve (NOT sciatic) | Gluteus medius/minimus → superior gluteal nerve | Gluteus maximus = always spared in sciatic nerve injury."},
/*32*/ {"q":"Coelic trunk branch is:","o":["Common hepatic artery","Splenic artery","Marginal artery","Aorta"],"a":0,"e":"The coeliac trunk (T12/L1) has three branches: left gastric artery, common hepatic artery, and splenic artery. The marginal artery (of Drummond) is formed from branches of the SMA and IMA, not the coeliac trunk.<br><br>Take Notes: coeliac trunk → left gastric + common hepatic + splenic arteries | Marginal artery (Drummond) → SMA + IMA anastomosis (not coeliac) | Common hepatic → hepatic proper + gastroduodenal | 'Left Hepatic Splenic' = coeliac trunk branches mnemonic."},
/*33*/ {"q":"A 24 years old married female having secondary amenorrhea, her FSH n LH levels are high, u/s of pelvis doesn't show abnormality. What can be possible cause?","o":["Ovarian tumor","Autoimmunity","Gonadal failure","Dysgerminoma"],"a":2,"e":"High FSH and LH with secondary amenorrhoea and normal pelvic USS indicates primary ovarian insufficiency (premature ovarian failure) — the ovaries fail to respond to gonadotropins, causing elevated FSH/LH (loss of negative feedback) with no follicular development.<br><br>Take Notes: high FSH + high LH + amenorrhoea + normal USS → primary ovarian insufficiency | Hypothalamic amenorrhoea → low FSH/LH | Pituitary failure → low FSH/LH | High gonadotropins + no ovarian response = ovarian/gonadal failure."},
/*34*/ {"q":"Edema in liver cirrhosis patient is due to:","o":["Decrease Oncotic Pressure","Increase Oncotic Pressure","Increase Permeability","Increase interstitial hydrostatic pressure"],"a":0,"e":"Liver cirrhosis causes oedema primarily through hypoalbuminaemia (reduced albumin synthesis → reduced plasma oncotic pressure) and portal hypertension (increased hydrostatic pressure in portal territory → ascites). The dominant systemic oedema mechanism is reduced oncotic pressure.<br><br>Take Notes: cirrhosis oedema → ↓albumin → ↓oncotic pressure (dominant systemic cause) | Portal hypertension → ascites (local hydrostatic increase) | Na retention → secondary hyperaldosteronism (contributes) | Reduced oncotic pressure = the primary cirrhosis oedema mechanism."},
/*35*/ {"q":"Diabetic patient present with nausea and headache who is receiving antidepressants. Became polyuric with decrease sodium. Cause is:","o":["Psychogenic polydipsia","SIADH","Central DI","Nephrogenic DI"],"a":3,"e":"Antidepressants (especially SSRIs and TCAs) can cause SIADH — inappropriate ADH secretion causing hyponatraemia and water retention (oliguria, not polyuria). However, polyuria with hyponatraemia points to nephrogenic DI — the kidneys cannot respond to ADH, losing water despite adequate ADH levels.<br><br>Take Notes: polyuria + hyponatraemia → nephrogenic DI (kidneys unresponsive to ADH) | SIADH → hyponatraemia + oliguria (water retention) | Central DI → polyuria + hypernatraemia (no ADH production) | Polyuria + low Na = nephrogenic DI pattern."},
/*36*/ {"q":"Patient has lipoma on posterior aspect of SCM, 5 cm relation to sternoclavicular joint. Which structure ligated leading to profuse bleeding?","o":["External jugular vein","Internal jugular vein","Common carotid artery","2nd part of subclavian artery"],"a":3,"e":"A mass at the posterior SCM near the sternoclavicular joint, 5 cm from the joint, is at the level of the subclavian artery (2nd part). The 2nd part of the subclavian artery runs posterior to the scalenus anterior, and iatrogenic ligation causes massive upper limb ischaemia and profuse bleeding.<br><br>Take Notes: posterior SCM + sternoclavicular region + 5cm → 2nd part subclavian artery at risk | External jugular → superficial, posterior to SCM but venous | Internal jugular → medial to SCM | 2nd part subclavian = the deep posterior SCM vessel."},
/*37*/ {"q":"Lower molecular weight Heparin activates which of following?","o":["Factor X","Factor IX","Anti thrombin 3","Plasminogen"],"a":2,"e":"Low molecular weight heparin (LMWH, e.g., enoxaparin) acts by activating antithrombin III (AT-III), which then irreversibly inhibits Factor Xa primarily. Unlike unfractionated heparin, LMWH has less effect on thrombin (Factor IIa). AT-III is the obligatory mediator.<br><br>Take Notes: LMWH → activates AT-III → inhibits Factor Xa (primarily) | UFH → activates AT-III → inhibits both Xa and IIa (thrombin) | AT-III = obligatory mediator for both heparin types | Anti-thrombin III = the heparin cofactor."},
/*38*/ {"q":"A 35 years old female presents with 6 month history of fingers turning pale in cold (Raynaud's phenomenon) also having mild dyspnea, no wheeze, tight skin with mild enlarged spleen, creatinine was high, urea also raised, ANA positive, HB 10, WBC and platelets normal. What is the diagnosis?","o":["Discoid lupus erythematous","Progressive Systemic Sclerosis","SLE","Sjogren Syndrome"],"a":1,"e":"Raynaud's phenomenon + tight skin (sclerodactyly) + raised creatinine (renal involvement) + ANA positive in a young woman = Progressive Systemic Sclerosis (scleroderma). Renal crisis is a life-threatening complication of scleroderma.<br><br>Take Notes: scleroderma → tight skin + Raynaud's + renal (raised creatinine) + ANA positive | SLE → malar rash + multi-organ + anti-dsDNA | Sjogren → sicca (dry eyes/mouth) | Tight skin + Raynaud's + renal = Progressive Systemic Sclerosis."},
/*39*/ {"q":"Patient at height dead space of one third of tidal volume. PCO2 of venous blood is 45. What will be EtCO2:","o":["30","40","25","60"],"a":0,"e":"End-tidal CO2 (EtCO2) approximates alveolar PCO2. If one-third of tidal volume is dead space (diluting alveolar gas with atmospheric CO2-free air), alveolar PCO2 is diluted. Venous PCO2 is 45 mmHg; arterial PCO2 is normally ~40; EtCO2 with dead space dilution is reduced to approximately 30 mmHg.<br><br>Take Notes: EtCO2 → approximates alveolar PCO2 | Increased dead space → dilutes alveolar CO2 → lowers EtCO2 | Normal EtCO2 = 35-45 mmHg | Dead space increase → EtCO2 falls below arterial PCO2."},
/*40*/ {"q":"Side effects of dicumarol is:","o":["Delayed clotting","Increase bleeding time","Decrease clotting time","Abnormal clotting"],"a":0,"e":"Dicumarol (a coumarin anticoagulant like warfarin) inhibits Vitamin K epoxide reductase, reducing synthesis of factors II, VII, IX, X. This prolongs PT and clotting time (delayed clotting). Bleeding time is a test of platelet function — not affected by coumarin anticoagulants.<br><br>Take Notes: dicumarol/warfarin → prolongs PT (delayed clotting) | Bleeding time → NOT affected (platelet function intact) | Antidote → Vitamin K + PCC | Delayed clotting = the correct side effect (not 'increased bleeding time')."},
/*41*/ {"q":"Mother milk is deficient in:","o":["Vitamin C","Vitamin A","Casein","Vitamin D"],"a":0,"e":"Breast milk is deficient in Vitamin D and Vitamin K — not Vitamin C (which is present). However, per this source, Vitamin C is listed as deficient. Most standardly, breast milk is deficient in Vitamin D (and Vitamin K in early days), but the answer per source is Vitamin C (Chatterjea biochemistry).<br><br>Take Notes: breast milk deficient in → Vitamin D + Vitamin K (standard teaching) | Per Chatterjea → Vitamin C listed as deficient | Vitamin D deficiency → rickets in exclusively breastfed infants (especially low sunlight) | Supplement Vitamin D for all breastfed infants."},
/*42*/ {"q":"Systolic phase of cardiac cycle correspond to the following component of ECG:","o":["QRS complex","QR interval","ST segment","PR Segment"],"a":0,"e":"The QRS complex represents ventricular depolarisation, which triggers ventricular systole. Systole begins at the R wave (ventricular depolarisation) and ends at T wave completion (repolarisation). The QRS complex is the ECG marker of systole onset.<br><br>Take Notes: QRS → ventricular depolarisation = onset of systole | T wave → ventricular repolarisation = end of systole | PR interval → AV nodal delay (atrial depolarisation to ventricular) | QRS = systole starts here."},
/*43*/ {"q":"45-year man presented with sudden onset of retrosternal chest pain with sweating and breathlessness. O/E BP was 90/60, pulse was 110/min, low volume. Most likely diagnosis is:","o":["Dissecting aneurysm","MI","Pneumonia","Pulmonary embolism"],"a":1,"e":"Sudden retrosternal crushing chest pain + diaphoresis + dyspnoea + hypotension + tachycardia with low volume pulse = acute MI with cardiogenic shock. This is the classic STEMI/NSTEMI haemodynamic presentation.<br><br>Take Notes: retrosternal pain + diaphoresis + hypotension + tachycardia → acute MI (cardiogenic shock) | Dissecting aneurysm → tearing pain radiating to back + unequal BP in arms | PE → pleuritic pain + raised JVP + hypoxia | Retrosternal + diaphoresis + shock = MI until proven otherwise."},
/*44*/ {"q":"Regarding preferential thorough fare channel correct statement is:","o":["Small caliber","Having smooth muscles","Open on demand","Present at origin of precapillary sphincter"],"a":1,"e":"Thoroughfare channels (preferential channels) are direct connections between arterioles and venules that bypass true capillaries. They have smooth muscle in their walls (unlike true capillaries which have none) and remain open to allow baseline flow even when capillary beds are closed.<br><br>Take Notes: thoroughfare channels → have smooth muscle (unlike true capillaries) | Always open (not 'on demand') | True capillaries → no smooth muscle, controlled by precapillary sphincters | Smooth muscle present = the key distinguishing feature of thoroughfare channels."},
/*45*/ {"q":"Adrenal secretory adenoma leads to:","o":["Hyperkalemia","Acedemia","Hypocalcemia","Hyponatremia"],"a":2,"e":"An adrenal secretory adenoma secreting aldosterone (Conn's syndrome) causes hypokalaemia, metabolic alkalosis, hypertension, and sodium retention. Hypocalcaemia results because high aldosterone causes high H+ loss → alkalosis → Ca2+ shifts to bound form → ionised Ca2+ falls. Per this source, Ans: C = Hypocalcemia.<br><br>Take Notes: Conn's adenoma (aldosterone) → Na retention + K loss + metabolic alkalosis | Alkalosis → Ca2+ binding increases → ionised hypocalcaemia | Hyponatraemia → opposite (Na is retained) | Hypokalaemia is more classic but hypocalcaemia via alkalosis is the mechanism here."},
/*46*/ {"q":"Lymphatic drainage of external nose and anterior part of nasal cavity is:","o":["Submandibular lymph nodes","Deep cervical lymph nodes","Retropharyngeal lymph nodes","Occipital lymph nodes"],"a":0,"e":"The external nose and anterior nasal cavity drain to the submandibular lymph nodes. The posterior nasal cavity and nasopharynx drain to the retropharyngeal and upper deep cervical nodes. This distinction is clinically important for nasal carcinoma staging.<br><br>Take Notes: external nose + anterior nasal cavity → submandibular nodes | Posterior nasal cavity → retropharyngeal + upper deep cervical | Remaining nasal cavity → upper deep cervical | Submandibular = external nose drainage."},
/*47*/ {"q":"A female with sign and symptoms of hyperprolactinoma was diagnosed with pituitary adenoma. The growth of this tumor anteriorly will compress which structure?","o":["Cavernous sinus","Optic nerve","Optic chiasma","Optic tract"],"a":1,"e":"The pituitary gland lies in the sella turcica. Anterior extension of a pituitary adenoma compresses the optic nerve (which runs above and anterior to the pituitary), causing visual field defects. Superior extension compresses the chiasma (bitemporal hemianopia).<br><br>Take Notes: pituitary adenoma superior → optic chiasma compression (bitemporal hemianopia) | Pituitary adenoma anterior → optic nerve compression | Lateral → cavernous sinus (CN III, IV, VI palsies) | Anterior extension = optic nerve = the answer here."},
/*48*/ {"q":"Main support of pelvic viscera?","o":["Levator ani","Uterosacral ligament","Anal sphincter","Pelvic diaphragm"],"a":0,"e":"The levator ani (pelvic diaphragm) is the primary muscular support of the pelvic viscera. It forms a muscular hammock supporting the bladder, rectum, and uterus. Its weakness causes pelvic organ prolapse. Ligaments provide secondary support.<br><br>Take Notes: levator ani = pelvic diaphragm → primary muscular pelvic floor support | Uterosacral ligaments → secondary support (suspend uterus) | Levator ani weakness → pelvic organ prolapse | Levator ani = the main pelvic floor support."},
/*49*/ {"q":"Melanoma invade orbital cavity through:","o":["Sclera","Optic nerve","Emissary vein","Retina"],"a":2,"e":"Uveal malignant melanoma (most common primary intraocular tumour in adults) invades the orbital cavity through the emissary veins — small vascular channels that penetrate the sclera and connect the uveal vasculature to orbital vessels, providing a pathway for extrascleral extension.<br><br>Take Notes: uveal melanoma → orbital invasion via emissary veins | Most common primary intraocular tumour in adults | Sclera itself → invaded but emissary veins = the specific pathway | Emissary veins = the orbital invasion route for uveal melanoma."},
/*50*/ {"q":"Anti GnRH harmone secreted in dark is:","o":["Cortisol","Thyroxin","Insulin","Melatonin"],"a":3,"e":"Melatonin is secreted by the pineal gland in darkness (regulated by the suprachiasmatic nucleus via the light-dark cycle). Melatonin suppresses GnRH secretion from the hypothalamus, inhibiting the reproductive axis — this is why melatonin is considered an anti-GnRH hormone in dark conditions.<br><br>Take Notes: melatonin → secreted in darkness by pineal gland | Suppresses GnRH → anti-reproductive effect | Explains seasonal breeding in animals (short days = high melatonin = reproductive suppression) | Melatonin = darkness hormone = GnRH suppressor."}
,
/*51*/ {"q":"Most potent antioxidant is:","o":["Vit E","Vitamin K","Vit C","Vit A"],"a":0,"e":"Vitamin E (alpha-tocopherol) is the most potent fat-soluble antioxidant, protecting cell membranes from lipid peroxidation by scavenging free radicals. It is the primary antioxidant defence in lipid compartments including RBC membranes and LDL particles.<br><br>Take Notes: Vitamin E → most potent fat-soluble antioxidant (lipid membrane protection) | Vitamin C → most potent water-soluble antioxidant | Glutathione → primary intracellular antioxidant | Vitamin E deficiency → haemolytic anaemia + neurological defects."},
/*52*/ {"q":"A patient presents with acute painful swelling in front of his ear. O/E parotid gland is enlarged. Which nerve is involved?","o":["Maxillary nerve","Ophthalmic nerve","Greater auricular nerve","Mandibular nerve"],"a":2,"e":"Pain from parotid gland pathology is transmitted via the great auricular nerve (C2-C3, from cervical plexus) — a purely sensory nerve supplying the skin over the parotid, ear lobule, and angle of the jaw. The auriculotemporal nerve (V3) also contributes to parotid innervation.<br><br>Take Notes: parotid pain → great auricular nerve (C2-C3, cervical plexus) | Parotid secretomotor → glossopharyngeal (CN IX) via auriculotemporal | Facial nerve (CN VII) → runs through parotid (motor to face) | Greater auricular = the sensory nerve to parotid region."},
/*53*/ {"q":"Right shift of O2 dissociation curve is due to:","o":["Increase PH","Increase H ions","Decrease CO2","Decrease Temperature"],"a":1,"e":"The oxygen-haemoglobin dissociation curve shifts right (decreased O2 affinity, better tissue oxygen delivery) with: decreased pH (increased H+ — Bohr effect), increased CO2, increased temperature, and increased 2,3-DPG. Increased H+ is the primary Bohr effect trigger.<br><br>Take Notes: right shift → ↑H+ + ↑CO2 + ↑temperature + ↑2,3-DPG (CADET) | Right shift → ↓O2 affinity → better tissue O2 unloading | Left shift → opposite (↑pH, ↓CO2, ↓temp, fetal HbF) | Increased H ions (acidosis) = the Bohr effect = right shift."},
/*54*/ {"q":"A sea diver after diving develops shortness of breath and joint pain. Cause is:","o":["Lactic Acidosis","Nitrogen bubbles in blood","Excessive fatigue","Excess CO2"],"a":1,"e":"Decompression sickness (the bends) occurs when a diver ascends too rapidly — dissolved nitrogen comes out of solution forming gas bubbles in blood and tissues. Joint pain ('the bends'), skin itching, and neurological symptoms result. Slow ascent prevents this.<br><br>Take Notes: decompression sickness → nitrogen bubbles in blood/tissues from rapid ascent | Joint pain + dyspnoea + skin itching = classic symptoms | Treatment → hyperbaric oxygen chamber | Nitrogen = the dissolved gas responsible (not CO2)."},
/*55*/ {"q":"Which is not oncogene and cause gene amplification?","o":["RET","HER 2","APC","Myc"],"a":2,"e":"APC (adenomatous polyposis coli) is a tumour suppressor gene — mutations cause familial adenomatous polyposis and colorectal cancer. It is NOT an oncogene. RET, HER-2, and Myc are oncogenes — gain-of-function mutations or amplification drives cancer.<br><br>Take Notes: APC → tumour suppressor (NOT oncogene) — loss of function causes FAP and CRC | HER-2 → oncogene (amplified in breast CA) | Myc → oncogene (amplified in Burkitt's) | RET → oncogene (MEN 2) | APC = tumour suppressor = the odd one out."},
/*56*/ {"q":"Right lower limb paralysis is caused by:","o":["Left MCA","ACA","PCA","Communicating artery"],"a":1,"e":"The anterior cerebral artery (ACA) supplies the medial surface of the frontal and parietal lobes, where the motor and sensory homunculus represents the leg and foot. ACA occlusion causes contralateral leg weakness/paralysis — left ACA → right leg paralysis.<br><br>Take Notes: ACA → supplies medial cortex → leg + foot area of homunculus | MCA → lateral cortex → face + arm area | Right lower limb paralysis → left ACA occlusion | ACA = leg motor cortex = the lower limb artery."},
/*57*/ {"q":"A 35 year male usually goes to Dubai and has H/O immoral sexual activities and doesn't use any protection. Has problem in walking in dark and loses balance, absent light reflexes, no pain sensation. Most likely diagnosis:","o":["UMNL","Tabes dorsalis","LMNL","Syringomyelia"],"a":1,"e":"Tabes dorsalis (tertiary syphilis) causes degeneration of the dorsal columns and dorsal roots, producing: loss of proprioception (ataxia worsening in dark, positive Romberg), absent reflexes (dorsal root damage), Argyll Robertson pupils (light-near dissociation), and painless foot ulcers.<br><br>Take Notes: tabes dorsalis → dorsal column + dorsal root degeneration (tertiary syphilis) | Walking difficulty in dark + no light reflex + no pain = tabes dorsalis triad | Argyll Robertson pupil → accommodates but doesn't react to light | Tabes = syphilis = posterior cord disease."},
/*58*/ {"q":"Patient after RTA having urine incontinence. Which segment of Spinal cord is damaged:","o":["Above Sacral","Sympathetic","Sacral segment","None"],"a":2,"e":"Bladder and urethral sphincter control originates from the sacral micturition centre (S2-S4). Damage to the sacral cord causes lower motor neuron bladder (atonic, overflow incontinence). Injury above the sacral cord causes UMN bladder (spastic/hyperreflexic).<br><br>Take Notes: sacral cord (S2-S4) → micturition centre → damage = atonic/overflow incontinence (LMN) | Above sacral → spastic bladder (UMN) | Urinary incontinence post-RTA → sacral cord injury until proven otherwise | Sacral segment = the bladder control centre."},
/*59*/ {"q":"UMN lesion of facial nerve all true except:","o":["Forehead spare","Devitaion of mouth angle toward side of lesion","One eye spared","None"],"a":1,"e":"UMN facial nerve lesion (above facial nucleus) spares the forehead due to bilateral cortical representation of the frontalis muscle. The mouth deviates AWAY from the lesion (contralateral weakness), not toward it. One eye is spared (forehead/eye area bilaterally represented).<br><br>Take Notes: UMN facial palsy → forehead and eye spared (bilateral cortical supply) | Mouth deviation → away from lesion (contralateral lower face weakness) | LMN facial palsy (Bell's) → entire ipsilateral face affected including forehead | Deviation toward lesion = FALSE = the 'except' answer."},
/*60*/ {"q":"Person with difficulty in swallowing, there was some white growth inside esophagus with pseudohyphae. Likely reason is:","o":["Candidiasis","Aspergillosis","Histoplasmosis","Mucor"],"a":0,"e":"Oesophageal candidiasis presents with dysphagia and odynophagia with white plaques and pseudohyphae on endoscopy — the most common oesophageal infection in immunocompromised patients. Pseudohyphae are the key histological finding distinguishing Candida from other fungi.<br><br>Take Notes: white oesophageal plaques + pseudohyphae → Candida albicans | Most common oesophageal infection in AIDS/immunocompromised | Aspergillus → septate hyphae (no pseudohyphae) | Pseudohyphae = Candida = oesophageal candidiasis."},
/*61*/ {"q":"Regarding Erythrocytes true is:","o":["Hydrolysed when placed in hypertonic soln","Produce ankyrin and spectrin","Use carbohydrate aerobically","Produce ankyrin spectrin"],"a":1,"e":"RBCs produce ankyrin and spectrin — the cytoskeletal proteins that maintain the biconcave disc shape and deformability. Spectrin forms a meshwork attached to the lipid bilayer via ankyrin and band 4.1 protein. Hereditary spherocytosis results from spectrin/ankyrin deficiency.<br><br>Take Notes: RBC cytoskeleton → spectrin + ankyrin + band 3 + band 4.1 | Hereditary spherocytosis → spectrin/ankyrin deficiency | RBCs in hypertonic → crenate/shrink (not hydrolyse) | Ankyrin + spectrin = the RBC membrane skeleton proteins."},
/*62*/ {"q":"CA pancreas patient is admitted in ward. His brother is not letting patient know that patient has cancer because according to his brother it would kill the patient even faster. The patient's family is going to come to hospital to discuss. What will you do?","o":["Give family time to discuss among themselves","Tell his brother it will be dishonesty with patient, family and medical staff","Will ask him to mind his own business","None"],"a":1,"e":"Medical ethics requires patient autonomy and truth-telling. A competent adult patient has the right to know their diagnosis. Colluding with family to withhold the diagnosis violates the principles of autonomy, honesty, and informed consent.<br><br>Take Notes: patient autonomy → competent patients have the right to their diagnosis | Collusion with family → violates autonomy + non-maleficence | Approach → acknowledge family concerns, then support disclosure to patient | Truth-telling = fundamental medical ethics principle."},
/*63*/ {"q":"Vessel at the base of Bladder lies in which ligament?","o":["Dorsolateral","Ventrolateral","Ventromedial","Ligament teres"],"a":0,"e":"The vessels supplying the base of the bladder run in the lateral ligaments of the bladder (lateral true ligaments), which are also called the lateral vesical ligaments. These contain the inferior vesical vessels (from internal iliac) on the dorsolateral aspect of the bladder.<br><br>Take Notes: bladder base vessels → lateral vesical ligaments (dorsolateral) | Internal iliac → source of inferior vesical arteries | Median umbilical ligament → urachus remnant (anterior midline) | Dorsolateral = where bladder base vascular pedicle runs."},
/*64*/ {"q":"A 6 year old child presented with weakness and lethargy. MCV 59 and Hb 6.8. Diagnose is:","o":["Megaloblastic anemia","Folate deficiency","Iron deficiency anemia","Sideroblastic anemia"],"a":2,"e":"Low MCV (microcytic, 59) + low Hb (6.8) in a 6-year-old child = iron deficiency anaemia — the most common cause of microcytic hypochromic anaemia in children. Megaloblastic and folate deficiency cause macrocytic (high MCV) anaemia.<br><br>Take Notes: microcytic anaemia (low MCV) in child → iron deficiency (most common) | Megaloblastic/folate → macrocytic (high MCV) | Sideroblastic → microcytic but ring sideroblasts on bone marrow | Low MCV + child = iron deficiency until proven otherwise."},
/*65*/ {"q":"Hypospadias is due to abnormality of:","o":["Urogenital Sinus","Urogenital Folds","Urachus","Bladder"],"a":1,"e":"Hypospadias results from incomplete fusion of the urogenital folds (urethral folds) on the ventral aspect of the developing penis. The urethral opening is located on the ventral surface of the penis rather than at the tip. Associated with inguinal hernia and cryptorchidism.<br><br>Take Notes: hypospadias → failure of urogenital fold fusion (ventral urethral opening) | Epispadias → failure of genital tubercle fusion (dorsal opening) | Urogenital folds → form the penile urethra by fusion | Urogenital folds = hypospadias = ventral urethral defect."},
/*66*/ {"q":"Study involved to rule out causes of rare disease is:","o":["Cohort","Case control","Clinical trials","Retrospective cohort"],"a":1,"e":"Case-control studies are the most efficient design for studying rare diseases — they start with cases (disease present) and matched controls (no disease) and look backward for exposures. Cohort studies require enormous sample sizes to observe enough rare disease events.<br><br>Take Notes: rare disease study → case-control (most efficient) | Cohort → good for rare exposures, not rare diseases | Randomised controlled trial → interventions (not aetiology) | Case-control = the go-to for rare disease epidemiology."},
/*67*/ {"q":"In median episiotomy perineal body is damaged. If perineal body cut which muscle damage?","o":["Bulbospongiosis and Superficial transverse perineal","Pubotectalis","Pubococcygeus","Anal sphincter"],"a":0,"e":"The perineal body is the fibromuscular node at the centre of the perineum where multiple muscles converge: bulbospongiosus, superficial transverse perineal, external anal sphincter, and deep transverse perineal. Median episiotomy damages bulbospongiosus and superficial transverse perineal primarily.<br><br>Take Notes: perineal body → junction of bulbospongiosus + superficial transverse perineal + EAS | Median episiotomy → damages anterior perineal body structures | Medio-lateral episiotomy → avoids midline (less perineal body damage) | Bulbospongiosus + superficial transverse perineal = the muscles damaged in median episiotomy."},
/*68*/ {"q":"Which of the following is released at the synapse between pain fibers and incoming pain fibers and inhibitory fibers in CNS spinal cord?","o":["Histamine","Glutamate","Substance P","Enkephalin"],"a":3,"e":"Enkephalins (endogenous opioids) are released from interneurons in the substantia gelatinosa (lamina II) to inhibit pain transmission. They act presynaptically on C-fibre terminals and postsynaptically on spinothalamic neurons — the basis of the gate control theory and opioid analgesia.<br><br>Take Notes: pain inhibition at dorsal horn → enkephalins (endogenous opioids) | Gate control theory → enkephalin interneurons gate pain signals | Substance P → excitatory neurotransmitter FROM C fibres (promotes pain) | Enkephalin = pain inhibitor; Substance P = pain promoter."},
/*69*/ {"q":"Patient is taking warfarin and starting to bleed. What is treatment of it?","o":["Heparin","Platelets","TPA","Vitamin K + FFP"],"a":3,"e":"Warfarin overdose causing bleeding is reversed with Vitamin K (restores clotting factor synthesis, takes 12-24 hours) and Fresh Frozen Plasma (FFP) or Prothrombin Complex Concentrate (PCC) for immediate factor replacement. Cryoprecipitate is used for fibrinogen/Factor VIII deficiency.<br><br>Take Notes: warfarin reversal → Vitamin K (delayed, 12-24h) + FFP or PCC (immediate) | Heparin reversal → protamine sulphate | TPA → thrombolytic (opposite of what's needed) | Vitamin K + FFP = the complete warfarin reversal strategy."},
/*70*/ {"q":"A girl during menstruation develops high grade fever because she was using tampons. Organism responsible is:","o":["Staph aureus","Staph epidermidis","Actinomyces","Gonorrhea"],"a":0,"e":"Toxic shock syndrome (TSS) from tampon use is caused by Staphylococcus aureus producing TSST-1 (toxic shock syndrome toxin-1), a superantigen that massively activates T cells causing cytokine storm, fever, rash, hypotension, and multi-organ failure.<br><br>Take Notes: TSS + tampons → Staph aureus (TSST-1 superantigen) | Strep TSS → Group A Strep (SPEA toxin) — no tampon link | Superantigen → bypasses normal antigen presentation → massive T cell activation | TSST-1 = Staph aureus = tampon-associated TSS."},
/*71*/ {"q":"A female presented with colli flower like lesion in perineum and diagnose of Condyloma Acuminatum made it is caused by:","o":["HSV 1","HSV 2","HPV","Gonorrhea"],"a":2,"e":"Condyloma acuminata (genital warts) are caused by HPV types 6 and 11 — low-risk HPV types causing benign exophytic (cauliflower-like) genital lesions. HPV 16/18 cause flat dysplastic lesions with high malignant potential.<br><br>Take Notes: Condyloma acuminata → HPV 6 and 11 (low risk, benign cauliflower warts) | HPV 16/18 → high risk, cervical/anal SCC | Condyloma latum → secondary syphilis (flat, moist — different from acuminata) | Cauliflower lesion = condyloma acuminata = HPV 6/11."},
/*72*/ {"q":"Female 17 year old with primary amenorrhea, absent secondary sexual characteristics. O/E well develop normal breast and blind vagina. USG confirm absent uterus. Most likely karyotype of this is:","o":["CAH","Testicular feminization","Turner syndrome","Klinfelter syndrome"],"a":1,"e":"Normal breast development (oestrogen from testes), absent uterus, blind vagina, and primary amenorrhoea in a phenotypic female = androgen insensitivity syndrome (testicular feminisation) — 46,XY karyotype with non-functional androgen receptors. Müllerian structures are absent (AMH from testes).<br><br>Take Notes: normal breasts + absent uterus + blind vagina + primary amenorrhoea → androgen insensitivity (46,XY) | Turner syndrome → 45,XO (no breast development, streak ovaries) | AMH from testes → no uterus | Testicular feminisation = 46,XY = phenotypic female with absent uterus."},
/*73*/ {"q":"Early diagnose of preeclampsia done by:","o":["Cortisol monitoring","HbA1c","Early BP monitoring","Regular LFT"],"a":2,"e":"Pre-eclampsia is defined by new-onset hypertension (>140/90) after 20 weeks with proteinuria or end-organ damage. Early detection relies on regular blood pressure monitoring from booking. Elevated BP is the earliest and most reliable indicator preceding overt pre-eclampsia.<br><br>Take Notes: pre-eclampsia early detection → regular BP monitoring (most sensitive early sign) | Risk factors → first pregnancy + obesity + chronic HTN + renal disease | Urine protein (dipstick) → confirms proteinuria | BP monitoring = the primary screening tool for pre-eclampsia."},
/*74*/ {"q":"Which is the Pre eclampsia triggering factor?","o":["Fetal Endothelial dysfunction","Fetoplacental circulation compromise","Release of factor from placenta","Low oxygen"],"a":0,"e":"Pre-eclampsia is triggered by defective placentation — insufficient trophoblast invasion of spiral arteries causes placental ischaemia. Ischaemic placenta releases anti-angiogenic factors (sFlt-1, soluble endoglin) into maternal circulation, causing widespread endothelial dysfunction — the central mechanism.<br><br>Take Notes: pre-eclampsia → defective placentation → placental ischaemia → endothelial dysfunction | sFlt-1 (anti-VEGF) → released from ischaemic placenta → endothelial damage | Endothelial dysfunction → HTN + proteinuria + oedema | Fetal/placental endothelial dysfunction = the triggering mechanism."},
/*75*/ {"q":"How many days does it take for Spermatozoa to form Mature sperm:","o":["100 days","50 days","75 days","90 days"],"a":2,"e":"Complete spermatogenesis takes approximately 74-90 days: ~16 days spermatocytogenesis + ~24 days meiosis + ~24 days spermiogenesis + ~12 days epididymal transit. 75 days is the commonly cited clinical approximation.<br><br>Take Notes: spermatogenesis → ~74 days in seminiferous tubule | Epididymal maturation → ~12 days additional | Total ~87 days (some sources cite 75 days) | Chemotherapy effects on sperm → take 2-3 months to appear and recover."},
/*76*/ {"q":"Intrahepatic protein anabolism and extra hepatic catabolism:","o":["Cortisol","Glucagon","Epinephrine","Growth hormone"],"a":0,"e":"Cortisol has a unique metabolic profile: it promotes protein anabolism in the liver (increased hepatic protein and enzyme synthesis) while causing protein catabolism in peripheral tissues (muscle, skin, bone) — redirecting amino acids to the liver for gluconeogenesis.<br><br>Take Notes: cortisol → hepatic protein anabolism + peripheral protein catabolism | Cushing's → muscle wasting + thin skin + striae (peripheral catabolism) | GH → anabolic in muscle (IGF-1 mediated) | Cortisol = liver anabolism + peripheral catabolism = unique dual protein effect."},
/*77*/ {"q":"In hemostasis the word Gain is for:","o":["Negative feedback","Positive feedback","Exaggeration of the clotting mechanism","Child birth"],"a":2,"e":"The clotting cascade uses positive feedback amplification — once initiated, each step amplifies the next, rapidly generating large amounts of thrombin. This is described as 'gain' in haemostasis (amplification/exaggeration of the clotting mechanism). Fibrinolysis uses negative feedback to limit clot extension.<br><br>Take Notes: haemostasis 'gain' → positive feedback/amplification of clotting cascade | Thrombin → amplifies its own generation (activates factors V, VIII, XI) | Fibrinolysis → negative feedback (limits clot) | Gain in clotting = positive feedback = clotting cascade amplification."},
/*78*/ {"q":"Aspirin at low doses inhibit which of following?","o":["Inhibition of leukotrienes","Inhibit Collagen","PGI2","Inhibit TXA2"],"a":3,"e":"Low-dose aspirin (75-325 mg) irreversibly inhibits COX-1 in platelets, blocking TXA2 synthesis. TXA2 promotes platelet aggregation and vasoconstriction. This selective antiplatelet effect is the basis of aspirin's cardioprotective use. High-dose aspirin inhibits PGI2 as well.<br><br>Take Notes: low-dose aspirin → inhibits TXA2 (platelet COX-1 irreversibly) | TXA2 → vasoconstriction + platelet aggregation | PGI2 (prostacyclin) → protected at low doses (endothelial COX-1 regenerates) | TXA2 inhibition = the antiplatelet mechanism of low-dose aspirin."},
/*79*/ {"q":"Therapeutic dose of drug indicates:","o":["Potency","Safety","Efficacy","Dose"],"a":0,"e":"The therapeutic dose refers to the dose that produces the desired therapeutic effect in 50% of patients (ED50) — this reflects the drug's potency. A more potent drug achieves the therapeutic effect at a lower dose. Efficacy refers to the maximum effect achievable regardless of dose.<br><br>Take Notes: potency → dose required for therapeutic effect (ED50) | Efficacy → maximum effect achievable (ceiling effect) | Therapeutic index → ED50/LD50 (safety ratio) | Therapeutic dose = potency = how little you need for effect."},
/*80*/ {"q":"Patient presented with peripheral tingling numbness, diplopia and visual disturbance diagnosed with demyelination disease. What type of nervous system cells are affected in this disease?","o":["Oligodendrocytes","Schwan cells","Astrocytes","Glial cells"],"a":0,"e":"Multiple sclerosis (demyelination of the CNS) is caused by autoimmune destruction of oligodendrocytes — the myelin-producing cells of the CNS. Schwann cells produce myelin in the peripheral nervous system (affected in Guillain-Barré, not MS).<br><br>Take Notes: CNS demyelination (MS) → oligodendrocytes destroyed | PNS demyelination (GBS) → Schwann cells destroyed | Oligodendrocytes → myelinate up to 50 axons each | Oligodendrocyte destruction = MS = the CNS demyelinating cell."},
/*81*/ {"q":"Patient had Cough and X-ray shows hilar lymphadenopathy, non caseating granuloma and there is rash on lower limb. Diagnose is:","o":["Sarcoidosis","TB","Syphilis","Leprosy"],"a":0,"e":"Bilateral hilar lymphadenopathy + non-caseating granulomas + erythema nodosum (lower limb rash) = sarcoidosis. This triad (Löfgren syndrome) is pathognomonic. TB causes caseating granulomas.<br><br>Take Notes: sarcoidosis → bilateral hilar LN + non-caseating granulomas + erythema nodosum (Löfgren syndrome) | TB → caseating granulomas (cheesy centre) | Non-caseating = sarcoid; caseating = TB | Bilateral hilar LN + non-caseating = sarcoidosis."},
/*82*/ {"q":"Pregnant lady presented with rheumatic fever. Which of the following is characteristic feature of rheumatic fever in this lady?","o":["Mitral stenosis","Mitral regurgitation","Aortic stenosis","Aortic regurgitation"],"a":0,"e":"Mitral stenosis is the most common valvular lesion of chronic rheumatic heart disease, resulting from repeated bouts of rheumatic fever causing fibrous thickening and commissural fusion of the mitral leaflets. Acute rheumatic fever causes mitral regurgitation.<br><br>Take Notes: chronic rheumatic heart disease → mitral stenosis (most common) | Acute rheumatic fever → mitral regurgitation (valvulitis) | Rheumatic fever affects mitral > aortic > tricuspid > pulmonary | Mitral stenosis = chronic RHD = the classic long-term complication."},
/*83*/ {"q":"Child having hydrocephalus due to defect in:","o":["Meninges","Ependymal cells","Epidural space","Arachnoid Granulations"],"a":3,"e":"Communicating hydrocephalus results from impaired CSF reabsorption at the arachnoid granulations (Pacchionian bodies), which drain CSF into the venous sinuses. Obstruction of granulations (post-meningitis, post-haemorrhage) causes CSF accumulation and raised ICP.<br><br>Take Notes: arachnoid granulations → CSF reabsorption into superior sagittal sinus | Blocked arachnoid granulations → communicating hydrocephalus | Obstructive hydrocephalus → CSF pathway blockage (aqueduct stenosis) | Arachnoid granulations = the CSF reabsorption site = communicating hydrocephalus cause."},
/*84*/ {"q":"Cannon A wave is associated with:","o":["Tricuspid regurgitation","Pulmonary stenosis","Mitral regurgitation","Pulmonary embolism"],"a":0,"e":"Cannon A waves are giant JVP waveforms occurring when the right atrium contracts against a closed tricuspid valve — seen in complete heart block, VT, and junctional rhythms where atrial and ventricular contractions are dissociated. In tricuspid regurgitation, there is a large CV wave, not cannon A.<br><br>Take Notes: cannon A wave → atrium contracts against closed tricuspid valve (AV dissociation) | Seen in → complete heart block + VT + junctional rhythms | Large V wave → tricuspid regurgitation | Cannon A wave = AV dissociation = the JVP sign of heart block/VT."},
/*85*/ {"q":"In which condition there is no relation between P and QRS complex:","o":["Tricuspid regurgitation","Pulmonary stenosis","Mitral regurgitation","Pulmonary embolism"],"a":3,"e":"Complete heart block (3rd degree AV block) causes complete dissociation between P waves (atrial rate) and QRS complexes (ventricular escape rate) — there is no fixed PR relationship. P waves and QRS march independently at different rates.<br><br>Take Notes: complete heart block → P and QRS completely dissociated (no relationship) | 1st degree → prolonged fixed PR | 2nd degree Mobitz I → progressively lengthening PR then dropped QRS | Complete heart block = P marches independently of QRS."},
/*86*/ {"q":"Artery palpated between trachea and sternohyoid:","o":["EJV","ECA","Common carotid artery","IJV"],"a":2,"e":"The common carotid artery is palpated in the carotid triangle, between the trachea medially and the sternocleidomastoid laterally. It lies alongside (and slightly behind) the sternohyoid muscle, making it accessible in this groove for pulse assessment and surgical access.<br><br>Take Notes: common carotid artery → palpated between trachea and SCM/sternohyoid | Carotid pulse → at C4 level (thyroid cartilage) | Internal carotid → no branches in neck | Common carotid = the palpable neck pulse between trachea and sternohyoid."},
/*87*/ {"q":"Superior thyroid artery originates from:","o":["External Carotid Artery","Thyrocervical trunk","Subclavian artery","Internal carotid artery"],"a":0,"e":"The superior thyroid artery is the first branch of the external carotid artery (ECA), arising just below the level of the hyoid bone. It supplies the upper pole of the thyroid and is closely related to the external laryngeal nerve (ELN) during thyroid surgery.<br><br>Take Notes: superior thyroid artery → first branch of ECA | Inferior thyroid artery → thyrocervical trunk (from subclavian) | ELN at risk → during ligation of superior thyroid artery | Superior thyroid = ECA branch; inferior thyroid = subclavian (thyrocervical) branch."},
/*88*/ {"q":"A chronic pressure overload in the left ventricle due to aortic stenosis results in:","o":["Altered left ventricle distensibility","Decreased contractility","Left ventricular dilatation","Left ventricular hypertrophy"],"a":3,"e":"Aortic stenosis causes pressure overload on the left ventricle — the LV generates higher systolic pressure against increased resistance. This chronic pressure overload causes concentric LV hypertrophy (walls thicken without cavity dilation) as an adaptive response.<br><br>Take Notes: pressure overload (AS, HTN) → concentric LV hypertrophy (wall thickening, normal or reduced cavity) | Volume overload (AR, MR) → eccentric hypertrophy (wall thinning + cavity dilation) | AS → concentric hypertrophy | LV hypertrophy = the AS adaptive response."},
/*89*/ {"q":"Heart failure is commonly associated with/due to which of the following conditions:","o":["Fibrinous pericarditis","Hemopericardium","Pericardial effusion","Chylopericarditis"],"a":0,"e":"Fibrinous pericarditis is the most common form of pericarditis associated with conditions that cause heart failure — particularly post-MI (Dressler's syndrome), uraemia, and viral pericarditis. It produces the classic friction rub and positional chest pain.<br><br>Take Notes: fibrinous pericarditis → most common type (post-MI, uraemia, viral) | Haemopericardium → blood in pericardium (trauma, aortic dissection) | Pericardial effusion → fluid accumulation (can be transudative/exudative) | Fibrinous pericarditis = most common pericarditis type associated with heart failure."},
/*90*/ {"q":"Female came with schizophrenia Bp 110/70 using drug (phenothiazine) or this now with milky discharge from nipples. What is the cause?","o":["Microprolactinoma","Macroprolactinoma","Drug induced","Pheochromocytoma"],"a":2,"e":"Phenothiazines (antipsychotics) block D2 dopamine receptors, removing the tonic inhibition of prolactin by dopamine. This causes drug-induced hyperprolactinaemia with galactorrhoea (milky nipple discharge). This is the most common cause of drug-induced galactorrhoea.<br><br>Take Notes: phenothiazines → D2 blockade → removes dopamine inhibition of prolactin → hyperprolactinaemia + galactorrhoea | Also: metoclopramide, domperidone, haloperidol | Prolactinoma → galactorrhoea but not on antipsychotics | Drug-induced = most common cause of galactorrhoea in women on antipsychotics."},
/*91*/ {"q":"Highest chance of pneumothorax occurs while passing CVP line via?","o":["Right internal jugular vein","External jugular","Subclavian vein","Left External jugular vein"],"a":2,"e":"Subclavian vein catheterisation carries the highest risk of pneumothorax because the subclavian vein lies immediately posterior to the clavicle above the apex of the lung. Needle deviation inferiorly readily punctures the pleural apex. Internal jugular approach has lower pneumothorax risk.<br><br>Take Notes: subclavian vein CVC → highest pneumothorax risk (lung apex proximity) | Internal jugular → lower pneumothorax risk (more lateral from pleura) | Femoral vein → no pneumothorax risk | Subclavian = highest pneumothorax risk for CVP line."},
/*92*/ {"q":"Patient came in ER with chest pain. ECG normal, cardiac enzymes normal. Doctor advised thoracic cage X-RAY. Which one of these structures is cartilaginous and Amphiarthrosis joint?","o":["Manubriosternal","Costochondral","Xiphisternal","Sternocostal"],"a":0,"e":"The manubriosternal joint (sternal angle of Louis) is a secondary cartilaginous joint (symphysis/amphiarthrosis) united by fibrocartilage. It is the landmark for the 2nd rib, carina, aortic arch level, and T4/T5 disc level. It may occasionally ossify in old age.<br><br>Take Notes: manubriosternal joint → secondary cartilaginous (fibrocartilage) = amphiarthrosis | Costochondral → primary cartilaginous (hyaline) = synchondrosis | Sternal angle (Louis) → landmark: 2nd rib + carina + aortic arch | Manubriosternal = amphiarthrosis = the cartilaginous sternal joint."},
/*93*/ {"q":"Pericardiocentesis is best performed bypassing a needle through:","o":["The fourth intercostal space","The 4th and 5th intercostal space left to sternum","The second intercostal space at the midclavicular line","The second intercostal space at the right sternal angle"],"a":1,"e":"Pericardiocentesis is performed by inserting the needle at the 4th-5th intercostal space left of the sternum, or via the subxiphoid approach (most common). The left parasternal approach avoids the left lung and internal mammary artery and provides direct access to the pericardial space.<br><br>Take Notes: pericardiocentesis → 4th-5th ICS left of sternum (or subxiphoid) | Subxiphoid approach → most common (between xiphoid and left costal margin, angled toward left shoulder) | Avoid right sternal angle → liver and right atrium at risk | Left parasternal 4th-5th ICS = the safe pericardiocentesis window."},
/*94*/ {"q":"Cell wall of gram positive cause septic shock. Which component of cell wall cause shock?","o":["Peptidoglycan","Techoic acid","Endotoxin","Phospholipid A"],"a":0,"e":"Gram-positive septic shock is mediated by peptidoglycan and lipoteichoic acid (LTA) from the bacterial cell wall, which activate TLR-2 (Toll-like receptor 2) on macrophages triggering cytokine release. Endotoxin (LPS) causes gram-negative shock via TLR-4.<br><br>Take Notes: gram-positive shock → peptidoglycan + lipoteichoic acid → TLR-2 | gram-negative shock → LPS (endotoxin) → TLR-4 | Exotoxin → gram-positive protein toxins (different mechanism) | Peptidoglycan = gram-positive cell wall shock mediator."},
/*95*/ {"q":"A young male had an RTA which resulted in a femur fracture. He died 5 days later. Autopsy showed cerebral petechiae. Diagnosis is:","o":["Sepsis","Fat embolism","Pulmonary embolism","Myocardial dysfunction"],"a":1,"e":"Fat embolism syndrome occurs 24-72 hours after long bone fractures — fat globules enter circulation, causing pulmonary involvement (dyspnoea), cerebral petechiae (neurological signs), and petechial rash. Cerebral petechiae on autopsy after a femur fracture is pathognomonic of fat embolism.<br><br>Take Notes: fat embolism → long bone fracture → cerebral petechiae + petechial rash + respiratory distress | Occurs 24-72 hours post-fracture | PE → wedge-shaped lung infarct (not petechiae) | Cerebral petechiae after femur fracture = fat embolism syndrome."},
/*96*/ {"q":"Patient with history of severe chest pain crushing in nature radiating to left arm of 2hr duration. ECG is inconclusive. Which cardiac enzyme will be raised?","o":["Myoglobin","CK-MB","CPK","Trop T"],"a":0,"e":"At 2 hours post-MI, myoglobin is the first cardiac biomarker to rise (within 1-3 hours, peaks at 6-9 hours). Troponin rises at 3-6 hours; CK-MB rises at 4-6 hours. With an inconclusive ECG at 2 hours, myoglobin is the only marker likely to be elevated.<br><br>Take Notes: myoglobin → rises first (1-3 hours), not cardiac-specific | CK-MB → rises 4-6 hours (more specific for cardiac) | Troponin T/I → rises 3-6 hours, most specific, persists 7-14 days | At 2 hours post-MI → myoglobin is the only elevated marker."},
/*97*/ {"q":"Hypertrophic cardiomyopathy typical feature is:","o":["Myocyte Necrosis","Myocyte disarray","Systolic Dysfunction","Decrease TPR"],"a":1,"e":"Hypertrophic cardiomyopathy (HCM) is characterised histologically by myocyte disarray (chaotic, whorled arrangement of hypertrophied myocytes), interstitial fibrosis, and myocyte hypertrophy. It is caused by sarcomere protein mutations (most commonly beta-myosin heavy chain).<br><br>Take Notes: HCM histology → myocyte disarray + hypertrophy + interstitial fibrosis | Systolic function → typically preserved (diastolic dysfunction) | Most common cause of sudden cardiac death in young athletes | Myocyte disarray = the pathognomonic HCM finding."},
/*98*/ {"q":"Athletes will have?","o":["Increase SV","Increase SV and heart rate","Increase heart rate and decrease SV","Increase TPR"],"a":0,"e":"Trained athletes develop cardiac adaptations: increased stroke volume (eccentric hypertrophy, increased LV volume), bradycardia at rest, increased VO2 max, and increased cardiac output during exercise. Resting HR is lower despite same or higher cardiac output.<br><br>Take Notes: athlete's heart → increased SV + resting bradycardia (same CO) | Eccentric LV hypertrophy → increased cavity size → increased preload → increased SV (Frank-Starling) | TPR → decreased during exercise (vasodilation) | Increased SV + decreased HR = athlete's cardiac adaptation."},
/*99*/ {"q":"Athletes have enlarged heart size comparatively and increased stroke volume instead. Their muscles need same amount of energy and having cardiac output approximately same as that in normal individuals. What can be the reason for this phenomenon?","o":["Increase SV","Increase SV and heart rate","Decrease heart rate and increase SV","Increase TPR"],"a":2,"e":"Athlete's paradox: same resting cardiac output as normal individuals but achieved differently — lower resting heart rate + higher stroke volume. The enlarged heart (eccentric hypertrophy) fills more volume per beat, compensated by a lower resting rate maintaining the same CO.<br><br>Take Notes: athlete resting CO = normal (5 L/min) | Achieved by → ↑SV + ↓HR (not ↑HR) | Larger LV cavity → more preload → more SV via Frank-Starling | Decreased HR + increased SV = the athlete's resting cardiac adaptation."},
/*100*/ {"q":"Fastest mechanism for BP changes is:","o":["CNS ischemic response","Baroreceptor","Cortisol","RAAS"],"a":1,"e":"Baroreceptors (carotid sinus and aortic arch) provide the fastest blood pressure regulation, responding within seconds to acute BP changes. They signal via CN IX and X to the cardiovascular centre, adjusting HR and vasomotor tone nearly instantaneously.<br><br>Take Notes: fastest BP regulation → baroreceptors (seconds) | Intermediate → RAAS (minutes to hours) | Slowest → aldosterone/fluid shifts (hours to days) | Baroreceptor = the fastest BP control mechanism = the acute reflex."}
,
/*101*/ {"q":"After a road traffic accident massive blood loss patient undergoes shock MAP < 60mmhg. What will activate now?","o":["RAAS","CNS ischemic response","Release of Renin","Baroreceptor reflex mechanism"],"a":1,"e":"At MAP < 60 mmHg, baroreceptors are no longer effective (below their operating range). The CNS ischaemic response activates — ischaemia of the vasomotor centre triggers maximal sympathetic discharge causing intense vasoconstriction to protect vital organs. This is the 'last ditch' BP defence mechanism.<br><br>Take Notes: MAP <60 → CNS ischaemic response (baroreceptors overwhelmed) | Cushing's reflex (HTN + bradycardia) → raised ICP version of same mechanism | Baroreceptors → effective only 60-180 mmHg | CNS ischaemic response = last resort BP mechanism."},
/*102*/ {"q":"Cytokeratin is an intermediate filament found in cells but is most commonly used for detection of?","o":["Neoplasia","Degree of metaplasia or dysplasia","To check rate of proliferation","For staging of disease"],"a":0,"e":"Cytokeratins are intermediate filaments specific to epithelial cells. Immunohistochemistry for cytokeratin (AE1/AE3 or CAM5.2) is used to identify epithelial tumours (carcinomas) and confirm neoplasia — distinguishing carcinoma from sarcoma, lymphoma, or melanoma on biopsy.<br><br>Take Notes: cytokeratin → epithelial intermediate filament → marks carcinomas | Vimentin → mesenchymal (sarcomas) | S-100 → neural/melanocytic | LCA (CD45) → lymphoma | Cytokeratin = carcinoma marker = epithelial neoplasia detection."},
/*103*/ {"q":"Carcinoma of cervix diagnosis by:","o":["Capsule invasion","Invasion to basement membrane","Intact basement membrane","Increase E cadherin"],"a":1,"e":"The transition from carcinoma in situ (CIS) to invasive cervical carcinoma is defined by invasion through the basement membrane into the underlying stroma. Once the basement membrane is breached, the tumour is invasive and carries metastatic potential.<br><br>Take Notes: invasive carcinoma → basement membrane invasion | CIS → intact basement membrane (confined to epithelium) | E-cadherin loss → promotes invasion (not increase) | Basement membrane invasion = the defining criterion of invasive cervical carcinoma."},
/*104*/ {"q":"Feature of mineralocorticoid tumor is:","o":["Hyperkalemia","Hypokalemia","Hypotension","Hyponatremia"],"a":1,"e":"Mineralocorticoid-secreting tumour (Conn's syndrome/primary hyperaldosteronism) causes hypokalaemia (aldosterone drives K+ excretion in collecting duct), hypertension, metabolic alkalosis, and mild hypernatraemia — not hypotension.<br><br>Take Notes: Conn's (mineralocorticoid tumour) → hypokalaemia + hypertension + metabolic alkalosis | Hypokalaemia → muscle weakness + arrhythmias + polyuria | Addison's → hyperkalaemia + hyponatraemia (opposite) | Hypokalaemia = the defining serum finding of mineralocorticoid excess."},
/*105*/ {"q":"After ovulation, the oocyte is in which phase of cell cycle?","o":["Metaphase of Meiosis II","Prophase of first meiotic division","Prophase of 2nd meiotic division","Metaphase of first meiotic division"],"a":2,"e":"After ovulation, the secondary oocyte is arrested at metaphase of meiosis II. It remains in this arrested state until fertilisation, when the sperm triggers completion of meiosis II and formation of the mature egg (ootid) and second polar body.<br><br>Take Notes: ovulation → secondary oocyte released arrested at metaphase of meiosis II | Fertilisation → triggers completion of meiosis II | Primary oocyte → arrested at prophase I (from birth to ovulation) | Metaphase II arrest = the ovulated oocyte's state."},
/*106*/ {"q":"Gastrocnemius size is reduced after cast applied for few weeks of fracture is most likely due to:","o":["Decrease Blood supply","Decrease muscle caliber","Denervation atrophy","Decrease protein synthesis and increase degradation"],"a":3,"e":"Disuse atrophy from immobilisation in a cast causes reduced protein synthesis and increased protein degradation in the immobilised muscle. This leads to decreased muscle fibre size (atrophy) without denervation. Denervation atrophy is faster and more severe.<br><br>Take Notes: immobilisation/disuse atrophy → ↓protein synthesis + ↑protein degradation | Denervation atrophy → faster + more severe (loss of trophic factors) | Disuse → reduced mechanical load → reduced mTOR signalling | Decreased synthesis + increased degradation = disuse atrophy mechanism."},
/*107*/ {"q":"Feature of well differentiated Squamous cell carcinoma is:","o":["Cytokeratin","Myc gene","Rb 53","Keratin pearls"],"a":3,"e":"Well-differentiated SCC shows keratin pearls (concentric whorls of squamous cells with central keratinisation) — the hallmark of squamous differentiation and good differentiation. Poorly differentiated SCC lacks these. Cytokeratin is the general epithelial marker, but keratin pearls are specific to well-differentiated SCC.<br><br>Take Notes: well-differentiated SCC → keratin pearls (concentric squamous whorls with central keratin) | Cytokeratin → general carcinoma marker (not specific to differentiation grade) | Keratin pearls = the histological signature of well-differentiated SCC | Poorly differentiated SCC → no pearls."},
/*108*/ {"q":"A patient has A fib and MI on autopsy. What is likely:","o":["HTN","DM","Trauma","Prolong immobilization"],"a":3,"e":"Prolonged immobilisation after MI causes venous stasis (deep vein thrombosis) → pulmonary embolism, and in the setting of AF, systemic thromboemboli. On autopsy, the combination of AF + MI findings with embolic complications points to prolonged immobilisation as the precipitating risk factor for thrombosis.<br><br>Take Notes: AF + MI + immobilisation → high thromboembolism risk (stasis + hypercoagulability) | AF → left atrial thrombus → systemic emboli | Post-MI immobilisation → DVT/PE risk | Prolonged immobilisation = Virchow's stasis component = thromboembolism risk."},
/*109*/ {"q":"Patient of cervical lymphadenopathy CXR shows bilateral hilar lymphadenopathy. Biopsy shows typical granulomatous necrosis of submandibular and sublingual glands. Diagnosis is:","o":["TB","Syphilis","Leprosy","Sarcoidosis"],"a":3,"e":"Bilateral hilar lymphadenopathy + non-caseating granulomas in submandibular and sublingual glands = sarcoidosis. Heerfordt's syndrome (uveoparotid fever) is sarcoidosis involving salivary glands, eyes, and facial nerve. The biopsy finding of granulomas in salivary glands is characteristic.<br><br>Take Notes: sarcoidosis → bilateral hilar LN + salivary gland granulomas (Heerfordt's) | TB → caseating granulomas (not typical of salivary glands bilaterally) | Sjögren's → lymphocytic infiltrate (not granulomas) | Bilateral hilar + salivary gland granulomas = sarcoidosis."},
/*110*/ {"q":"What is placebo affect:","o":["Doctor know the drug","Subject doesn't know the drug","Subject know the drug","It is actual treatment"],"a":1,"e":"The placebo effect occurs when a patient experiences a therapeutic benefit from an inert treatment — the subject does not know they are receiving a placebo (inactive substance). The double-blind design hides this from both patient and investigator.<br><br>Take Notes: placebo → inert treatment, subject doesn't know it's inactive | Placebo effect → subjective improvement without pharmacological mechanism | Single-blind → subject unaware | Double-blind → both subject and investigator unaware | Subject doesn't know the drug = placebo condition."},
/*111*/ {"q":"Immunity against Covid-19 and Tumor cells is of:","o":["Neutrophils","NK cells","Macrophages","Basophil"],"a":1,"e":"Natural Killer (NK) cells provide innate immunity against virally infected cells (including SARS-CoV-2) and tumour cells, without requiring prior sensitisation or MHC presentation. They recognise cells with reduced MHC-I expression (virally infected/tumour cells) and kill via perforin/granzyme.<br><br>Take Notes: NK cells → innate immunity against viruses + tumour cells (no prior sensitisation needed) | Kill mechanism → perforin + granzyme → apoptosis | Recognise → reduced MHC-I (stressed/infected/tumour cells) | NK cells = innate anti-tumour + anti-viral immunity."},
/*112*/ {"q":"A young girl with blisters on extremities type of fluid present between dermis and epidermis:","o":["Transudative","Serous","Exudative","Fibrinous"],"a":1,"e":"Blisters (bullae/vesicles) form between the dermis and epidermis, containing serous fluid (plasma ultrafiltrate). Serous fluid is clear, protein-poor, and forms in conditions like burns (first-degree blistering), insect bites, or autoimmune bullous diseases (pemphigus, pemphigoid).<br><br>Take Notes: skin blisters → serous fluid (clear, low protein) | Exudate → high protein (inflammation, infection) | Transudate → low protein (hydrostatic/oncotic imbalance) | Serous = clear blister fluid = the fluid type in skin blisters."},
/*113*/ {"q":"A patient is on radiotherapy. After that DNA damage. A gene which arrest in G1 phase progression. Defective unregulated growth occurs due to which?","o":["K-ras","N-myc","P53","Bcl-2"],"a":2,"e":"P53 is the 'guardian of the genome' — it arrests cell cycle at G1/S checkpoint when DNA damage is detected, allowing repair before replication. If damage is irreparable, P53 triggers apoptosis. Radiotherapy-induced DNA damage that bypasses P53 function leads to unregulated growth.<br><br>Take Notes: P53 → G1/S checkpoint arrest after DNA damage | P53 mutation → most common mutation in human cancers | Radiotherapy → DNA damage → P53 activates → arrest or apoptosis | Defective P53 = cells bypass G1 arrest = unregulated proliferation."},
/*114*/ {"q":"Carcinoma that spread through vertebral arteries has which marker:","o":["CA 125","CA 19-9","AFP","PSA"],"a":3,"e":"Prostate carcinoma (PSA marker) metastasises to vertebrae via Batson's vertebral venous plexus. PSA (prostate-specific antigen) is the tumour marker for prostate cancer. Vertebral metastases from prostate cancer are typically osteoblastic (sclerotic), unlike most other metastases which are lytic.<br><br>Take Notes: vertebral metastasis via Batson's plexus → prostate CA (PSA marker) | PSA → most specific marker for prostate CA | CA-125 → ovarian | AFP → hepatocellular/germ cell | CA 19-9 → pancreatic | PSA = prostate = vertebral metastasis marker."},
/*115*/ {"q":"A security guard got gunshot injury on lower back. After physiotherapy and rehabilitation he had lost contralateral Pain/temp below the level of lesion and ipsilateral loss of Vibration. What is diagnosis?","o":["Damaged 1st dorsal root","Damaged ventral root","Brown sequard syndrome","Developing tabes dorsalis"],"a":2,"e":"Contralateral pain/temperature loss + ipsilateral vibration/proprioception loss below the lesion level = Brown-Séquard syndrome (spinal cord hemisection). The spinothalamic tract crosses within 2 segments; the dorsal column remains ipsilateral until the medulla.<br><br>Take Notes: Brown-Séquard → contralateral pain/temp loss + ipsilateral vibration/proprioception loss | Ipsilateral motor weakness (corticospinal) | Gunshot/stab = classic cause | Brown-Séquard = the crossed sensory pattern of cord hemisection."},
/*116*/ {"q":"Which inhalation anesthetics cause greater decrease vascular resistance:","o":["Isoflurane","Halothane","Cocaine","Procain"],"a":1,"e":"Halothane causes greater decrease in vascular resistance compared to other inhalation agents, increasing cerebral blood flow in the order: Halothane > Desflurane > Isoflurane > Sevoflurane. However, halothane is also the most hepatotoxic (halothane hepatitis) and arrhythmogenic.<br><br>Take Notes: vascular resistance decrease → Halothane > Desflurane > Isoflurane > Sevoflurane | Halothane → sensitises myocardium to catecholamines → arrhythmias | Halothane hepatitis → immune-mediated, can be fatal | Halothane = greatest vascular resistance decrease = greatest cerebral vasodilation."},
/*117*/ {"q":"Eustachian tube epithelium is:","o":["Pseudo stratified columnar ciliated","Pseudostratified columnar with stereocilia","Simple cuboidal","Simple squamous"],"a":0,"e":"The Eustachian (pharyngotympanic) tube is lined by pseudostratified columnar ciliated epithelium — the same as the respiratory tract. The cilia beat toward the nasopharynx, clearing secretions from the middle ear. Dysfunction causes serous otitis media (glue ear).<br><br>Take Notes: Eustachian tube → pseudostratified columnar ciliated (respiratory type) | Cilia beat → nasopharynx direction (clears middle ear) | Dysfunction → serous otitis media (glue ear) | Middle ear → simple cuboidal epithelium | Pseudostratified ciliated = Eustachian tube lining."},
/*118*/ {"q":"A woman presented with vulvar itching and pinkish purulent discharge. What is the cause?","o":["Trichomonas vaginalis","Chlamydia","Gonorrhea","Lactobacillus"],"a":0,"e":"Trichomonas vaginalis causes a frothy, yellow-green, malodorous vaginal discharge with vulvar itching and dysuria. The cervix appears as 'strawberry cervix' (punctate haemorrhages). Wet mount shows motile pear-shaped flagellated protozoa.<br><br>Take Notes: Trichomonas → frothy yellow-green discharge + vulvar itch + strawberry cervix | Gonorrhoea → purulent discharge + urethritis | Candida → thick white cottage-cheese discharge | Wet mount motile protozoa = Trichomonas = the frothy discharge cause."},
/*119*/ {"q":"Female patient with pain in first metatarsophalyngeal joint due to:","o":["Hypercalcemia","Gouty arthritis","Rheumatoid arthritis","Osteoarthritis"],"a":1,"e":"Podagra — acute monoarthritis of the first metatarsophalangeal joint — is the classic presentation of gout (hyperuricaemia). Urate crystals deposit in the joint causing intense inflammation. It is the most common joint affected in gout (~50% of first attacks).<br><br>Take Notes: 1st MTP joint pain → gout (podagra) first until proven otherwise | Gout → negatively birefringent needle-shaped urate crystals | RA → symmetrical small joint (MCP/PIP, not MTP primarily) | Podagra = 1st MTP = gout = the classic joint."},
/*120*/ {"q":"Microtubules are present in:","o":["Mitochondria","Centrioles","Golgi body","Lysosomes"],"a":1,"e":"Microtubules are polymers of alpha and beta tubulin forming the cytoskeleton, spindle fibres, cilia, and flagella. Centrioles are composed of nine triplets of microtubules (9+0 arrangement) and organise the mitotic spindle. Cilia and flagella have 9+2 arrangement.<br><br>Take Notes: centrioles → 9 triplets of microtubules (9+0 arrangement) | Cilia/flagella → 9 doublets + 2 central (9+2) | Mitotic spindle → microtubules from centrioles/centrosomes | Centrioles = the microtubule-containing organelle."},
/*121*/ {"q":"Best Host defense in Alveoli is:","o":["Nasal Cilia","Lymphatics","Alveolar macrophages","IgA Secretion"],"a":2,"e":"Alveolar macrophages (dust cells) are the primary host defence in the alveoli, phagocytosing inhaled particles, bacteria, and debris. They are derived from circulating monocytes and are strategically positioned in the alveolar space where mucociliary clearance does not reach.<br><br>Take Notes: alveolar macrophages → primary alveolar defence (phagocytosis) | Mucociliary escalator → defends conducting airways (not alveoli) | IgA → mucosal defence in upper airways | Alveolar macrophages = the alveolar immune sentinel."},
/*122*/ {"q":"Regarding Fetal HB true is:","o":["More CO2 binding capacity","Less O2 binding capacity","More O2 binding capacity","Cause tachycardia"],"a":2,"e":"Foetal haemoglobin (HbF, alpha2-gamma2) has higher O2 affinity than adult HbF — HbF has reduced 2,3-DPG binding (gamma chains less sensitive), causing it to stay on the left of the O2 dissociation curve. This allows HbF to extract O2 from maternal HbA across the placenta.<br><br>Take Notes: HbF → higher O2 affinity than HbA (left-shifted curve) | Mechanism → gamma chains bind 2,3-DPG less → less right shift | Allows placental O2 transfer from mother to fetus | HbF higher O2 affinity = the foetal O2 acquisition advantage."},
/*123*/ {"q":"Norepinephrine synthesis requires which enzyme:","o":["Methyl transferase","Dopamine hydroxylase","Dopa decarboxylase","Isomerase"],"a":1,"e":"Norepinephrine is synthesised from dopamine by dopamine beta-hydroxylase (DBH) — this enzyme converts dopamine to norepinephrine in the catecholamine synthesis pathway: Phe → Tyr → DOPA → Dopamine → Norepinephrine → Epinephrine. DBH is located in vesicles of sympathetic nerve terminals and chromaffin cells.<br><br>Take Notes: dopamine → norepinephrine = dopamine beta-hydroxylase (DBH) | Norepinephrine → epinephrine = PNMT (phenylethanolamine N-methyl transferase, in adrenal medulla) | DOPA → dopamine = DOPA decarboxylase | DBH = the norepinephrine synthesis enzyme."},
/*124*/ {"q":"ADH Act mainly on:","o":["Distal tubule","Bowmen capsule","PCT","CT"],"a":0,"e":"ADH (vasopressin) acts on V2 receptors in the principal cells of the distal convoluted tubule (DCT) and collecting duct (CD), inserting aquaporin-2 water channels into the luminal membrane to increase water reabsorption and concentrate urine. The collecting duct is the primary site, but DCT is also affected.<br><br>Take Notes: ADH → V2 receptors → aquaporin-2 insertion → DCT + collecting duct | PCT → constitutively high water permeability (ADH-independent) | ADH deficiency → central DI (dilute polyuria) | Distal tubule + collecting duct = ADH action site."},
/*125*/ {"q":"Right Ventricle characteristic feature is:","o":["Pulmonary Trunk arises","Aorta Arises","Partial pressure of oxygen increases","Partial Pressure of CO2 decreases"],"a":0,"e":"The pulmonary trunk (main pulmonary artery) arises from the right ventricle and carries deoxygenated blood to the lungs. The RV has a crescent-shaped cross-section, thinner walls than the LV, and is the outflow chamber for the pulmonary circulation.<br><br>Take Notes: RV → pulmonary trunk arises (deoxygenated blood to lungs) | LV → aorta arises (oxygenated blood to body) | RV pressure → 25/8 mmHg | LV pressure → 120/8 mmHg | Pulmonary trunk = RV characteristic outflow = the diagnostic feature."},
/*126*/ {"q":"Broadmann area 3, 2, 1:","o":["Located only on medial side of cortex","Receive all special sensation","Receive all somatosensory sensation","Receive all motor sensation"],"a":2,"e":"Brodmann areas 3, 2, and 1 constitute the primary somatosensory cortex (S1) in the postcentral gyrus of the parietal lobe. They receive all contralateral somatosensory input (touch, pressure, pain, temperature, proprioception) in a somatotopic (homuncular) arrangement.<br><br>Take Notes: Brodmann 3,2,1 → primary somatosensory cortex (S1, postcentral gyrus) | Receives → all contralateral somatosensory modalities | Brodmann 4 → primary motor cortex (precentral gyrus) | 3,2,1 = somatosensory; 4 = motor."},
/*127*/ {"q":"Na absorption from basal lamina of kidney:","o":["Kefflux","Na influx","Na efflux","Na/k ATPs pump"],"a":3,"e":"Na+ reabsorption across the basolateral membrane of renal tubular cells occurs via the Na+/K+-ATPase pump — actively transporting 3 Na+ out and 2 K+ in, maintaining the low intracellular Na+ concentration that drives Na+ entry from the tubular lumen. This is the primary energy-consuming step in renal Na+ reabsorption.<br><br>Take Notes: basolateral Na+ transport → Na+/K+-ATPase (active, primary) | Luminal Na+ entry → passive (down concentration gradient via channels/cotransporters) | Na+/K+-ATPase → the engine of renal Na+ reabsorption | Basal lamina Na+ exit = Na+/K+-ATPase pump."},
/*128*/ {"q":"The yeast species that are resistant to echinocandins are?","o":["Candida albicans","Mucor","Candida auris","Aspergillus"],"a":2,"e":"Candida auris is an emerging multidrug-resistant yeast that shows resistance to all three classes of antifungals including echinocandins (which target beta-1,3-glucan synthase). It causes nosocomial outbreaks with high mortality in immunocompromised patients.<br><br>Take Notes: echinocandin resistance → Candida auris (MDR emerging pathogen) | Also resistant to → azoles + often amphotericin | Candida albicans → echinocandin sensitive | Mucor → intrinsically resistant to echinocandins AND azoles (treat with amphotericin) | C. auris = echinocandin-resistant yeast = emerging MDR pathogen."},
/*129*/ {"q":"A patient comes to ophthalmology clinics with complain of gradual loss of vision. His accommodation reflex was Present but light reflex was Lost:","o":["Presbyopia","Encephalitis","Hornor syndrome","3rd nerve injury"],"a":1,"e":"Light reflex present + accommodation reflex lost = Argyll Robertson pupil (tabes dorsalis/neurosyphilis). However, the question states accommodation present + light reflex LOST. This pattern (light reflex lost, accommodation intact) = Argyll Robertson pupil. Encephalitis can damage the light reflex pathways while sparing accommodation.<br><br>Take Notes: Argyll Robertson pupil → accommodates but does NOT react to light (neurosyphilis) | Horner's → miosis + ptosis + anhidrosis (sympathetic loss) | 3rd nerve palsy → fixed dilated pupil (both reflexes lost) | Light lost + accommodation present = Argyll Robertson = neurosyphilis."},
/*130*/ {"q":"Regarding hodgkin disease?","o":["Lymphocyte depleted are more common in young","Male have better prognosis","Bony lesions are lytic","Extra Menifestations are more common than hodgkin lymphoma"],"a":3,"e":"Hodgkin lymphoma has extra-nodal manifestations less commonly than non-Hodgkin lymphoma. However, systemic B symptoms (fever, night sweats, weight loss) are more prominent in Hodgkin's. Bony lesions in Hodgkin's are typically mixed lytic/sclerotic (ivory vertebra is classic), not purely lytic.<br><br>Take Notes: Hodgkin's vs NHL extra-nodal → NHL more common in extra-nodal sites | Hodgkin's → B symptoms prominent + contiguous nodal spread | Lymphocyte predominant HL → best prognosis (not depleted) | NHL > Hodgkin's for extra-nodal manifestations = the distinguishing feature."},
/*131*/ {"q":"Dobutamine opposed by:","o":["Norepinephrine","Propranolol","Labetalol","Propanolol"],"a":1,"e":"Dobutamine is a synthetic catecholamine acting primarily on beta-1 receptors (positive inotropy) with some beta-2 activity. Its effects are competitively opposed by propranolol (non-selective beta-blocker), which blocks both beta-1 and beta-2 receptors.<br><br>Take Notes: dobutamine → beta-1 agonist (primary) + beta-2 (secondary) | Opposed by → propranolol (non-selective beta-blocker) | Labetalol → alpha + beta blocker (also opposes but has alpha effects) | Propranolol = the direct competitive antagonist of dobutamine's beta effects."},
/*132*/ {"q":"Anthrax drug of choice:","o":["Aminoglycosides","Penicillin","Penicillamine","Ciprofloxacin"],"a":3,"e":"Ciprofloxacin (or doxycycline) is the drug of choice for anthrax (Bacillus anthracis), both for treatment and post-exposure prophylaxis. This was established during the 2001 anthrax mail attacks. Penicillin is an alternative for susceptible strains but fluoroquinolones are preferred empirically.<br><br>Take Notes: anthrax → ciprofloxacin (DOC) or doxycycline | Post-exposure prophylaxis → ciprofloxacin 60 days | Penicillin → alternative for penicillin-sensitive strains only | Ciprofloxacin = the anthrax DOC."},
/*133*/ {"q":"A group of students were studying difference between PO2 and PCO2 in different arteries of the body. They find major differences between:","o":["Aorta and Pulmonary Artery","Skeletal muscle arteriole and venule","Aorta and Left ventricle","Right and Left Ventricle"],"a":0,"e":"The greatest PO2/PCO2 difference is between the aorta (systemic arterial, PO2 ~95 mmHg, PCO2 ~40 mmHg) and the pulmonary artery (venous blood, PO2 ~40 mmHg, PCO2 ~46 mmHg). These represent fully oxygenated vs deoxygenated blood, providing the maximal gradient.<br><br>Take Notes: aorta → PO2 ~95, PCO2 ~40 (oxygenated systemic) | Pulmonary artery → PO2 ~40, PCO2 ~46 (deoxygenated) | Greatest difference → aorta vs pulmonary artery | Ventricular blood → same composition as their respective arteries."},
/*134*/ {"q":"In case of ARDS the ventilation is hampered as result of interstitial edema due to:","o":["Increased capillary permeability","Increased Hydrostatic pressure","Decrease capillary permeability","Decrease oncotic pressure"],"a":0,"e":"ARDS is characterised by diffuse alveolar damage causing increased pulmonary capillary permeability — protein-rich fluid floods the alveoli (exudative oedema). Unlike cardiogenic oedema (increased hydrostatic pressure), ARDS oedema has high protein content due to the permeability defect.<br><br>Take Notes: ARDS → increased capillary permeability → protein-rich (exudative) pulmonary oedema | Cardiogenic oedema → increased hydrostatic pressure → protein-poor (transudative) | ARDS criteria → acute onset + bilateral infiltrates + PaO2/FiO2 <300 + non-cardiogenic | Increased permeability = the ARDS mechanism."},
/*135*/ {"q":"Difference between root of right lung from left lung is:","o":["No of primary bronchi","No of artries","No of veins","No of nerves plexus"],"a":0,"e":"The right lung root has two pulmonary veins, one pulmonary artery, and one primary bronchus — but importantly the right main bronchus is eparterial (bronchus above the pulmonary artery), giving it no primary bronchus at the level used to count. The key difference is that the right lung has no primary bronchus at the root level (the right upper lobe bronchus branches above the artery).<br><br>Take Notes: right lung root → eparterial bronchus (right upper lobe bronchus branches above the pulmonary artery) | Left lung → hyparterial (both left bronchi branch below the artery) | Right root → no primary bronchus at same level as artery | Eparterial = right = the key root difference."},
/*136*/ {"q":"Diagnosed appendicular tumor which has mucinous secretion called Pseudomyxoma peritonei will spread:","o":["Lymph node","Venous","Arterial spread","Peritoneal seeding"],"a":3,"e":"Pseudomyxoma peritonei (gelatinous ascites from mucinous tumour) spreads by peritoneal seeding — mucinous tumour cells implant directly on peritoneal surfaces. It does not spread via lymphatics or blood vessels. The appendix (and ovary in females) are the most common primary sites.<br><br>Take Notes: pseudomyxoma peritonei → peritoneal/transcoelomic spread (mucinous implants on peritoneal surfaces) | Not lymphatic, not vascular | Primary → appendix or ovary | Seeding to other peritoneal sites = the pseudomyxoma spread mechanism."},
/*137*/ {"q":"Vitamin K deficiency causes increase in:","o":["PT","BT","CT","None"],"a":0,"e":"Vitamin K deficiency reduces synthesis of factors II, VII, IX, X (and proteins C and S). Factor VII has the shortest half-life, so PT (which tests the extrinsic/common pathway via Factor VII) rises first and most prominently. APTT also rises but PT is the most sensitive test.<br><br>Take Notes: Vitamin K deficiency → ↑PT (most sensitive, Factor VII shortest half-life) | Also ↑APTT (factors IX, X, II) | Bleeding time → NOT affected (platelet function normal) | PT rise = the earliest Vitamin K deficiency lab finding."},
/*138*/ {"q":"A patient cannot recognize objects with close eye. Lesion is in:","o":["Neocortex","Primary somaesthetic area","Secondary somaesthetic area","Frontal cortex"],"a":2,"e":"Inability to recognise objects by touch alone (astereognosis) with intact primary sensation indicates a lesion in the secondary somatosensory area (S2, in the parietal operculum). The primary somatosensory cortex (S1, areas 3,2,1) receives sensory input; S2 processes object recognition and discrimination.<br><br>Take Notes: astereognosis (can't recognise by touch) → secondary somatosensory cortex (S2) | Primary somatosensory (S1, 3,2,1) → receives raw sensory input | Parietal association cortex → spatial awareness + object recognition | S2 lesion = astereognosis = failure of tactile object recognition."},
/*139*/ {"q":"Sympathomimetic drug is which one following:","o":["Propanolol","Amphetamine","Nabivolol","Alfazocin"],"a":1,"e":"Amphetamine is a sympathomimetic — it releases norepinephrine and dopamine from presynaptic terminals and inhibits their reuptake, causing CNS stimulation and peripheral sympathetic effects (tachycardia, hypertension, mydriasis). Propranolol and nebivolol are beta-blockers (sympatholytics).<br><br>Take Notes: amphetamine → sympathomimetic (indirect, releases NE + dopamine, blocks reuptake) | Propranolol/nebivolol → beta-blockers (sympatholytics) | Alfuzosin → alpha-1 blocker (sympatholytic) | Amphetamine = the only sympathomimetic in the list."},
/*140*/ {"q":"6 years old girl presented to OPD with excessive facial and chest hairs, adult size external genitilia and deepening of voice. She also gives history of two siblings death suffering from same condition. Which enzyme deficiency leads to this?","o":["17-alpha hydroxylase deficiency","21 hydroxylase deficiency","11 B-hydroxylase deficiency","22 hydroxylase deficiency"],"a":1,"e":"21-hydroxylase deficiency (most common, ~90% of CAH) causes cortisol and aldosterone deficiency with androgen excess — virilisation (facial hair, deepened voice, clitoral enlargement) in females. The enzyme block diverts pregnenolone to androgens. Salt-wasting form is life-threatening in infancy.<br><br>Take Notes: 21-hydroxylase deficiency → most common CAH (90%) → ↑androgens → virilisation in females | 11-beta-hydroxylase → virilisation + hypertension (DOC accumulates) | 17-alpha-hydroxylase → no sex steroids + hypertension | 21-hydroxylase = CAH = female virilisation (starts with 2, causes salt-wasting + virilisation)."},
/*141*/ {"q":"HSV 2 causes which of following?","o":["CA Cervix","CA Endometrium","CA Ovary","CA Breast"],"a":0,"e":"HSV-2 (herpes genitalis) is associated with an increased risk of cervical carcinoma, though HPV (types 16 and 18) is the primary cause. HSV-2 acts as a cofactor by promoting oncogenic transformation in HPV-infected cervical cells. HSV-1 causes labial herpes and keratitis/encephalitis.<br><br>Take Notes: HSV-2 → cervical CA association (cofactor with HPV) | HPV 16/18 → primary cervical CA cause | HSV-1 → herpes labialis + keratitis + encephalitis | HSV-2 = genital herpes = cervical CA risk factor."},
/*142*/ {"q":"Conducting system of heart is located in which of following:","o":["Sulcus terminalis","Moderator band","Sub epicardium","Sub endocardium"],"a":3,"e":"The cardiac conducting system (SA node, AV node, Bundle of His, bundle branches, Purkinje fibres) is located in the subendocardial layer — just beneath the endocardium. This subendocardial position allows direct electrical contact with the ventricular myocardium.<br><br>Take Notes: conducting system → subendocardial position | SA node → upper sulcus terminalis (right atrium) | AV node → subendocardium of Koch's triangle | Bundle of His → subendocardium of IVS | Subendocardium = the conducting system location."},
/*143*/ {"q":"Heat loss is controlled by:","o":["Vasoconstriction of Skin vessels","Vasodilation of Skin vessels","Anterior Hypothalamus","Preoptic area"],"a":3,"e":"Heat loss is primarily controlled by the preoptic area of the anterior hypothalamus, which acts as the body's thermostat. When temperature rises, it triggers vasodilation of skin vessels, sweating, and inhibition of heat production — all mediated through this centre.<br><br>Take Notes: preoptic/anterior hypothalamus → heat loss centre (responds to elevated temperature) | Posterior hypothalamus → heat conservation (responds to cold) | Vasodilation of skin → mechanism of heat loss (controlled by preoptic area) | Preoptic area = the thermostat for heat dissipation."},
/*144*/ {"q":"Female with fever and sore throat and 60% B lymphocytes and B and T lymphocytes normal percentage in the blood?","o":["B lymphocytes 50%","T lymphocytes 80-90% and B lymphocytes 10-20%","B lymphocytes 90% and T lymphocytes 10%","T lymphocytes 20%"],"a":1,"e":"In peripheral blood, the normal lymphocyte distribution is approximately 70-80% T lymphocytes and 10-20% B lymphocytes. In infectious mononucleosis (EBV), atypical T lymphocytes (reactive) predominate, with relative changes in the normal T:B ratio. The normal reference is T 80-90%, B 10-20%.<br><br>Take Notes: normal blood lymphocytes → T cells 70-80% + B cells 10-20% | EBV (mono) → atypical lymphocytes (reactive T cells) | NK cells → ~5-15% | T cells dominate peripheral blood = the normal lymphocyte ratio."},
/*145*/ {"q":"In quiet respiration muscle which increase vertical diameter of thorax is increased by:","o":["Diaphragm","External intercostal","Internal intercostal","Accessory muscles"],"a":0,"e":"The diaphragm increases the vertical diameter of the thorax during quiet inspiration by contracting and descending. It accounts for approximately 75% of quiet tidal volume. The vertical dimension increase is the diaphragm's primary contribution to chest expansion.<br><br>Take Notes: vertical thoracic diameter → diaphragm (descends during inspiration) | Anterior-posterior diameter → external intercostals (bucket handle movement) | Diaphragm → 75% of quiet tidal volume | Diaphragm = vertical dimension increase = primary quiet breathing muscle."},
/*146*/ {"q":"Heinz bodies are found in:","o":["Hereditary spherocytosis","G6PD deficiency","Pyruvate kinase deficiency","Ciehosis"],"a":1,"e":"Heinz bodies are denatured, precipitated haemoglobin seen in G6PD deficiency — oxidative stress (drugs, infection) causes haemoglobin oxidation when NADPH-dependent glutathione protection is lost. They are removed by splenic macrophages producing 'bite cells'.<br><br>Take Notes: Heinz bodies → G6PD deficiency (oxidative haemolysis) | 'Bite cells' → spleen removes Heinz bodies | Spherocytes → hereditary spherocytosis | Sickle cells → SCD | Heinz bodies = G6PD = oxidative haemoglobin denaturation."},
/*147*/ {"q":"Development of breast alveoli and lobules is function of:","o":["Estrogen","Prolactin","Oxytocin","Progesterone"],"a":3,"e":"Progesterone (with prolactin) drives the development of breast alveoli and lobules (the secretory units). Oestrogen primarily stimulates ductal growth and proliferation. During pregnancy, progesterone and prolactin together fully develop the lobulo-alveolar system for lactation.<br><br>Take Notes: progesterone → alveoli and lobules development (secretory units) | Oestrogen → ductal proliferation and growth | Prolactin → milk synthesis and secretion | Oxytocin → milk ejection (letdown reflex) | Progesterone = alveolar/lobular development = the lobulo-alveolar hormone."},
/*148*/ {"q":"A patient exhibits signs of Myasthenia Gravis. What is best confirmatory test in him?","o":["Biopsy","EMG","Edrophonium","Ach receptors antibodies"],"a":1,"e":"EMG (electromyography) showing decremental response on repetitive nerve stimulation is the best confirmatory test for Myasthenia Gravis. Anti-AChR antibodies are specific but can be negative in seronegative MG. The edrophonium (Tensilon) test is a clinical test. EMG confirms the neuromuscular junction defect electrophysiologically.<br><br>Take Notes: MG confirmatory → EMG (decremental response on repetitive stimulation) | Anti-AChR antibodies → specific but 15% seronegative | Edrophonium test → clinical (brief improvement with AChE inhibitor) | EMG decremental response = the electrophysiological MG confirmation."},
/*149*/ {"q":"Good doctor patient relationship requires:","o":["Having sound medical knowledge","Updating skills","Show authority","Active listening"],"a":3,"e":"Active listening is the cornerstone of a good doctor-patient relationship — it involves fully concentrating on the patient, understanding their concerns, and responding empathetically. It builds trust, improves history-taking, and leads to better clinical outcomes and compliance.<br><br>Take Notes: good doctor-patient relationship → active listening (most important interpersonal skill) | Medical knowledge + technical skills → necessary but not sufficient | Show authority → undermines trust and patient autonomy | Active listening = the foundation of therapeutic communication."},
/*150*/ {"q":"Increase extracellular calcium causes which of these?","o":["Systolic arrest","Diastolic arrest","Both arrests","No significant effect on heart"],"a":0,"e":"Hypercalcaemia causes systolic arrest — excess calcium increases myocardial excitability and contractility, locking the heart in sustained systole. This is the opposite of hyperkalaemia, which causes diastolic arrest. The mnemonic: calcium causes contraction (systole); potassium causes relaxation (diastole).<br><br>Take Notes: hypercalcaemia → systolic arrest (calcium locks heart in contraction) | Hyperkalaemia → diastolic arrest (depolarisation block) | Memory: Ca = contraction = systolic; K = relaxation = diastolic | Systolic arrest = hypercalcaemia = the cardiac emergency of excess calcium."}
];
